// ── Gate global de prioridade LIVE ──────────────────────────────────────
// Cada esporte registra 'esporte' em _livePhase enquanto processa live matches.
// Antes do primeiro upcoming, chama _waitOthersLiveDone(self) — bloqueia até
// nenhum outro esporte ter live pendente. Garante que TODO live do sistema
// é analisado antes de qualquer upcoming de qualquer esporte.
const _livePhase = new Set();
async function _waitOthersLiveDone(self, timeoutMs = 3 * 60 * 1000) {
  const start = Date.now();
  while (true) {
    const others = [..._livePhase].filter(s => s !== self);
    if (others.length === 0) return;
    if (Date.now() - start > timeoutMs) {
      log('WARN', 'AUTO', `live-gate timeout (${self}), prosseguindo. others=${others.join(',')}`);
      return;
    }
    await new Promise(r => setTimeout(r, 500));
  }
}
function _livePhaseEnter(sport) { _livePhase.add(sport); }
function _livePhaseExit(sport)  { _livePhase.delete(sport); }

function _sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

// Settlement — roda a cada 10min (era 30min). ESPN/API de scores tipicamente já tem
// resultado 3-8min pós-match; 10min dá margem mínima com reciprocidade boa.
const SETTLEMENT_INTERVAL = parseInt(process.env.SETTLEMENT_INTERVAL_MS || String(10 * 60 * 1000), 10);
let lastSettlementCheck = 0;

// Line movement
const lineAlerted = new Map();
const marketTipSent = new Map(); // key: match|market|line|side → ts (dedup 24h)

// ── TTL sweep dos Maps "analyzed*" e dedup ──
// Sem isso eles crescem indefinidamente (cada matchId único vira uma entry e
// nunca sai). Em produção 24/7 isso vira leak silencioso de memória — 7-10 dias
// num scanner com 200 matches/dia já passa de 50k entries.
// Sweep a cada 1h: remove entries cuja ts é mais velha que TTL.
const ANALYZED_TTL_MS = parseInt(process.env.ANALYZED_TTL_MS || String(72 * 3600 * 1000), 10); // 72h
const MARKET_TIP_SENT_TTL_MS = parseInt(process.env.MARKET_TIP_SENT_TTL_MS || String(48 * 3600 * 1000), 10); // 48h
function _sweepTsMap(map, ttlMs, now) {
  if (!map || !map.size) return 0;
  let removed = 0;
  for (const [key, value] of map.entries()) {
    const ts = (value && Number(value.ts)) || (typeof value === 'number' ? value : 0);
    if (ts > 0 && (now - ts) > ttlMs) { map.delete(key); removed++; }
  }
  return removed;
}
function sweepAnalyzedMaps() {
  const now = Date.now();
  let total = 0;
  total += _sweepTsMap(analyzedMatches, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedMma, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedTennis, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedFootball, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedDota, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedCs, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedValorant, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedDarts, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedSnooker, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(analyzedTT, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(lolSeriesLastTip, ANALYZED_TTL_MS, now);
  total += _sweepTsMap(lineAlerted, ANALYZED_TTL_MS, now);
  // marketTipSent stora ts direto (number), não wrapped em objeto.
  if (marketTipSent.size) {
    for (const [key, ts] of marketTipSent.entries()) {
      if (Number.isFinite(ts) && (now - ts) > MARKET_TIP_SENT_TTL_MS) { marketTipSent.delete(key); total++; }
    }
  }
  // Gauge sizes per Map — visibilidade de leak in-flight via /health/metrics.
  try {
    const metrics = require('./lib/metrics');
    metrics.gauge('analyzed_size', analyzedMatches.size, { sport: 'lol' });
    metrics.gauge('analyzed_size', analyzedDota.size, { sport: 'dota2' });
    metrics.gauge('analyzed_size', analyzedCs.size, { sport: 'cs' });
    metrics.gauge('analyzed_size', analyzedValorant.size, { sport: 'valorant' });
    metrics.gauge('analyzed_size', analyzedTennis.size, { sport: 'tennis' });
    metrics.gauge('analyzed_size', analyzedFootball.size, { sport: 'football' });
    metrics.gauge('analyzed_size', analyzedMma.size, { sport: 'mma' });
    metrics.gauge('market_tip_sent_size', marketTipSent.size);
  } catch (_) {}
  if (total > 0) {
    try { log('DEBUG', 'MEM-SWEEP', `removed ${total} stale analyzed entries (TTL ${Math.round(ANALYZED_TTL_MS/3600000)}h)`); } catch (_) {}
  }
  return total;
}
// Inicia sweep periódico — só quando log() já está disponível (lazy evaluation
// do setInterval). Roda 1x por hora.
setInterval(() => { try { sweepAnalyzedMaps(); } catch (_) {} }, 60 * 60 * 1000);

// ── Metrics bridge bot.js → server.js ──
// Counters/gauges/timings registrados no bot.js (pollers, sweep, etc) ficam
// em processo SEPARADO do server.js. Sem este bridge, /health/metrics no
// server só mostra counters de endpoints (record-tip, /claude, settle).
// Cron 60s POST snapshot do _metrics local pra /metrics/ingest, com prefix
// 'bot' pra não colidir com counters do próprio server (ex: ai_call_ms vira
// bot:ai_call_ms só no server).
function _bridgeBotMetricsToServer() {
  try {
    const snap = _metrics.snapshot();
    // Skip se nada acumulou ainda
    if (Object.keys(snap.counters).length === 0
        && Object.keys(snap.timings).length === 0
        && Object.keys(snap.gauges).length === 0) return;
    const port = process.env.SERVER_PORT || process.env.PORT || 3000;
    const http = require('http');
    const payload = JSON.stringify({ snapshot: snap, prefix: 'bot' });
    const req = http.request({
      host: '127.0.0.1', port, path: '/metrics/ingest', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) },
      timeout: 4000,
    }, res => res.resume());
    req.on('error', () => {}); // server pode estar reiniciando
    req.on('timeout', () => req.destroy());
    req.write(payload); req.end();
  } catch (_) {}
}
setInterval(_bridgeBotMetricsToServer, 60 * 1000);
setTimeout(_bridgeBotMetricsToServer, 30 * 1000); // primeiro flush 30s pós-boot

// ── Memory watchdog (com auto-tune dinâmico) ──
// Monitora process.memoryUsage().rss e mantém histograma das últimas 7d
// (288 amostras × 5min × 7d). Threshold dinâmico = P95 baseline × 1.3 quando
// MEM_WATCHDOG_AUTO=true (default). Opt-out: MEM_WATCHDOG_DISABLED=true ou
// override hard via MEM_WATCHDOG_RSS_MB.
//
// Por que P95: P50 (mediana) seria muito sensível; P99 só pega spike único.
// P95 captura outlier real sem alarme falso. Margem 1.3x acomoda variance
// natural sem flagging baseline normal.
let _lastMemAlertDay = null;
const _rssSamples = []; // ring buffer
const RSS_SAMPLE_CAP = 7 * 24 * (60 / 5); // 7d × 24h × 12 amostras/h = 2016
function _percentile(arr, pct) {
  if (!arr.length) return null;
  const sorted = [...arr].sort((a, b) => a - b);
  const idx = Math.min(sorted.length - 1, Math.floor(sorted.length * pct));
  return sorted[idx];
}
function _memWatchdogTick() {
  if (/^(1|true|yes)$/i.test(String(process.env.MEM_WATCHDOG_DISABLED || ''))) return;
  try {
    const mem = process.memoryUsage();
    const rssMb = +(mem.rss / 1024 / 1024).toFixed(1);
    const heapMb = +(mem.heapUsed / 1024 / 1024).toFixed(1);
    try {
      const m = require('./lib/metrics');
      m.gauge('rss_mb', rssMb);
      m.gauge('heap_used_mb', heapMb);
    } catch (_) {}
    // Acumula sample no ring
    _rssSamples.push(rssMb);
    if (_rssSamples.length > RSS_SAMPLE_CAP) _rssSamples.shift();
    // Threshold: env hard override > auto-tune > default fallback
    let threshold;
    const hardEnv = parseFloat(process.env.MEM_WATCHDOG_RSS_MB);
    const autoOn = !/^(0|false|no)$/i.test(String(process.env.MEM_WATCHDOG_AUTO ?? 'true'));
    if (Number.isFinite(hardEnv) && hardEnv > 0) {
      threshold = hardEnv;
    } else if (autoOn && _rssSamples.length >= 144) { // 12h mínimo de amostras
      const p95 = _percentile(_rssSamples, 0.95);
      const margin = parseFloat(process.env.MEM_WATCHDOG_AUTO_MARGIN || '1.3');
      threshold = +(p95 * (Number.isFinite(margin) && margin > 1 ? margin : 1.3)).toFixed(1);
      try { require('./lib/metrics').gauge('rss_threshold_mb', threshold); } catch (_) {}
    } else {
      threshold = 800; // bootstrap antes de coletar amostras
    }
    if (rssMb < threshold) return;
    log('WARN', 'MEM-WATCHDOG', `RSS ${rssMb}MB > threshold ${threshold}MB (heap=${heapMb}MB, n=${_rssSamples.length} samples)`);
    // DM 1x/dia (dedup por today), só se ADMIN_IDS setado.
    const today = new Date().toISOString().slice(0, 10);
    if (_lastMemAlertDay === today || !ADMIN_IDS.size) return;
    _lastMemAlertDay = today;
    const routed = _pickTokenForAlert('system');
    const token = routed?.token;
    if (!token) return;
    const p50 = _percentile(_rssSamples, 0.5);
    const p95v = _percentile(_rssSamples, 0.95);
    const baselineNote = p50 != null
      ? `\nBaseline 7d: P50=${p50}MB, P95=${p95v}MB (${_rssSamples.length} samples)`
      : '';
    const msg = `⚠️ *Memory Watchdog*\n\nRSS: *${rssMb}MB* (threshold ${threshold}MB)\nHeap used: ${heapMb}MB${baselineNote}\n\n_Possível leak. Cheque /health/metrics gauges (analyzed_size, market_tip_sent_size). Considere restart se sustentado._`;
    for (const adminId of ADMIN_IDS) sendDM(token, adminId, msg).catch(e => log('DEBUG', 'MEM-WATCHDOG', `DM err ${adminId}: ${e.message}`));
  } catch (_) {}
}
setInterval(_memWatchdogTick, 5 * 60 * 1000);
setTimeout(_memWatchdogTick, 30 * 1000);

// Rejection ring buffer — debug quando "tips não estão saindo".
// Formato: { ts, sport, teams, reason, extra }
const _rejections = [];
const REJECTIONS_MAX = 200;
// Metrics counters cross-process — wirado em logRejection + tip dispatch.
// /health/metrics endpoint expõe acumulado + rolling 1h.
const _metrics = require('./lib/metrics');
function logRejection(sport, teams, reason, extra = {}) {
  _rejections.unshift({ ts: Date.now(), sport, teams, reason, extra });
  if (_rejections.length > REJECTIONS_MAX) _rejections.length = REJECTIONS_MAX;
  try { _metrics.incr('rejection', { sport: sport || 'unknown', reason: reason || 'unknown' }); } catch (_) {}
}
function getRejections(sportFilter, limit = 50) {
  let list = _rejections;
  if (sportFilter) list = list.filter(r => r.sport === sportFilter);
  return list.slice(0, Math.max(1, Math.min(limit, REJECTIONS_MAX)));
}

// ── Bug reporter: escala erros silenciosos (ReferenceError/TypeError/SyntaxError)
// pra DM admin. Catches DEBUG em código de produção viraram black hole — esse
// helper loga ERROR + dedup por signature (10min) + DM pra bugs reais de código.
const _bugReports = new Map(); // sig → ts
const BUG_REPORT_COOLDOWN_MS = 10 * 60 * 1000;
// Throws de flow-control esperados (gap de dados, não bugs) — descem pra DEBUG
// e nunca escalam DM. Extensível via ENV REPORT_BUG_BENIGN_PATTERNS (csv).
const BENIGN_ERROR_PATTERNS = [
  /no serve stats available/i,
  /no stats available/i,
  /no data available/i,
  /insufficient data/i,
  /no odds/i,
  /no matchups?/i,
  /no fixtures?/i,
  /no lineup/i,
  /timeout/i,
  /ETIMEDOUT|ENETUNREACH|ECONNREFUSED|ENOTFOUND|EAI_AGAIN/i,
];
const _extraBenign = String(process.env.REPORT_BUG_BENIGN_PATTERNS || '')
  .split(',').map(s => s.trim()).filter(Boolean).map(s => new RegExp(s, 'i'));
function _isBenignErr(msg) {
  return BENIGN_ERROR_PATTERNS.some(r => r.test(msg)) || _extraBenign.some(r => r.test(msg));
}

function reportBug(module, err, ctx = {}) {
  const name = err?.name || 'Error';
  const msg = err?.message || String(err);
  const stack = err?.stack || '';
  const sig = `${module}|${name}|${msg.slice(0, 120)}`;
  const now = Date.now();

  const ctxStr = Object.keys(ctx).length ? ' | ' + JSON.stringify(ctx).slice(0, 300) : '';

  // Data-gap esperado → DEBUG + no-DM.
  if (_isBenignErr(msg)) {
    log('DEBUG', module, `${name}: ${msg}${ctxStr}`);
    return;
  }

  log('ERROR', module, `${name}: ${msg}${ctxStr}`);

  const last = _bugReports.get(sig) || 0;
  if (now - last < BUG_REPORT_COOLDOWN_MS) return;
  _bugReports.set(sig, now);

  // DM só para bugs de código (não para timeouts/rede/env).
  const codeBugNames = new Set(['ReferenceError', 'TypeError', 'SyntaxError', 'RangeError']);
  const isCodeBug = codeBugNames.has(name) || /is not defined|is not a function|Cannot read|Cannot set/.test(msg);
  if (!isCodeBug) return;

  if (!ADMIN_IDS.size) return;
  try {
    const token = resolveAlertsToken();
    if (!token) return;
    const stackHead = stack.split('\n').slice(0, 5).join('\n');
    const ctxLine = Object.keys(ctx).length ? `\nctx: \`${JSON.stringify(ctx).slice(0, 200)}\`` : '';
    const dm = `🐛 *Bug detectado*\n*${module}* — \`${name}\`\n\`${msg}\`${ctxLine}\n\n\`\`\`\n${stackHead}\n\`\`\``;
    for (const id of ADMIN_IDS) sendDM(token, id, dm).catch(e => log('WARN', 'BUG-REPORT-FAIL', `adminId=${id}: ${e.message}`));
  } catch (_) {}
}

/**
 * Pipeline health check: conta rejeições por sport na última hora.
 * Se sport tem >=PIPELINE_STUCK_THRESHOLD rejections + 0 tips sent → log WARN.
 * Sinaliza gates apertados demais ou modelo desligado.
 */
const _lastStuckAlert = {}; // sport → ts (cooldown 2h entre alertas)

// Policy rejections — não são "pipeline travada", são gates intencionais (ITF
// excluído, odds antigas, prefilter cortando edge fraca). Exclusas do count.
const POLICY_REJECTIONS = new Set([
  'itf_exclusion',
  'non_slam_disabled', // TENNIS_NON_SLAM_DISABLED=true é policy ativa (Brier non-top 0.23+); mesma natureza de itf_exclusion
  'odds_stale',
  'odds_out_of_range', // odds fora do range configurado — gate intencional per-sport
  'odds_bucket_block', // bucket de odd bloqueado via ODDS_BUCKET_BLOCK (leak confirmado em backtest)
  'ml_prefilter_edge',
  'segment_gate',
  'ai_no_edge',        // IA decidiu não entrar — decisão válida
  'ia_no_edge',        // alias PT usado no MMA (bot.js:10811) — mesma semântica
  'boxing_disabled',   // MMA_ALLOW_BOXING=false é default permanente (sem boxing Elo)
  'future_week_not_alta', // luta futura + conf<ALTA = gate intencional
]);

// Threshold per-sport via ENV. Tennis tem universo gigante (ITF/Challenger/ATP
// rodando simultâneo) → threshold maior evita falsos positivos.
function _stuckThresholdFor(sport) {
  const envKey = `PIPELINE_STUCK_THRESHOLD_${sport.toUpperCase()}`;
  if (process.env[envKey]) return parseInt(process.env[envKey], 10);
  const defaults = { tennis: 60, table_tennis: 50, mma: 30 };
  if (defaults[sport]) return defaults[sport];
  return parseInt(process.env.PIPELINE_STUCK_THRESHOLD || '20', 10);
}

function runPipelineStuckCheck() {
  const ONE_HOUR = 60 * 60 * 1000;
  const COOLDOWN = 2 * ONE_HOUR;
  const now = Date.now();
  const cutoff = now - ONE_HOUR;

  // Conta apenas rejeições alertáveis (exclui policy gates).
  const byySport = {};
  for (const r of _rejections) {
    if (r.ts < cutoff) break;
    if (POLICY_REJECTIONS.has(r.reason)) continue;
    byySport[r.sport] = (byySport[r.sport] || 0) + 1;
  }

  for (const [sport, count] of Object.entries(byySport)) {
    if (count < _stuckThresholdFor(sport)) continue;
    // Conta tips enviadas esse sport na última hora (active only)
    try {
      const tipsRow = db.prepare(`
        SELECT COUNT(*) AS n FROM tips
        WHERE sport = ?
          AND (archived IS NULL OR archived = 0)
          AND sent_at >= datetime('now', '-1 hour')
      `).get(sport === 'cs' ? 'cs' : sport === 'dota2' ? 'esports' : sport);
      if (tipsRow.n > 0) continue;
      // Sport tem muitas rejections + 0 tips. Alert com cooldown.
      if ((now - (_lastStuckAlert[sport] || 0)) < COOLDOWN) continue;
      _lastStuckAlert[sport] = now;
      // Top reasons (exclui policy rejections — já filtradas do count)
      const reasons = {};
      for (const r of _rejections) {
        if (r.ts < cutoff || r.sport !== sport) continue;
        if (POLICY_REJECTIONS.has(r.reason)) continue;
        reasons[r.reason] = (reasons[r.reason] || 0) + 1;
      }
      const topReasons = Object.entries(reasons).sort((a, b) => b[1] - a[1]).slice(0, 3).map(([r, n]) => `${r}×${n}`).join(' · ');
      log('WARN', 'PIPELINE-STUCK', `${sport}: ${count} rejections / 0 tips na última hora. Top: ${topReasons}. Verificar gates.`);
      // DM admin — sinaliza pipeline travada (gate apertado demais ou modelo off).
      if (ADMIN_IDS.size) {
        try {
          const token = resolveAlertsToken();
          if (token) {
            const dm = `🚨 *Pipeline travada* — *${sport}*\n${count} rejeições / 0 tips na última hora\nTop motivos: ${topReasons}\n_Verificar gates ou modelo desligado._`;
            for (const id of ADMIN_IDS) sendDM(token, id, dm).catch(e => log('WARN', 'PIPELINE-ALERT-FAIL', `adminId=${id}: ${e.message}`));
          }
        } catch (_) {}
      }
    } catch (_) {}
  }
}
const LINE_CHECK_INTERVAL = 30 * 60 * 1000;
let lastLineCheck = 0;



// Live notifications (esports)
const notifiedMatches = new Map();
let lastLiveCheck = 0;
const LIVE_CHECK_INTERVAL = 60 * 1000; // 1 minute
let lastDotaLiveCheck = 0;
const DOTA_LIVE_CHECK_INTERVAL = 5 * 60 * 1000; // 5 min (evita spam de requests)
const RE_ANALYZE_INTERVAL = 10 * 60 * 1000; // 10 min between re-analyses of same live match
// Pré-jogo: intervalo maior para economizar tokens IA (odds pré-jogo mudam pouco).
// Default 2h (antes 30min). Configurável via LOL_UPCOMING_INTERVAL_MIN.
// Live continua usando RE_ANALYZE_INTERVAL (10min) — mercado muda rápido.
