// ── Live Storm Manager (cron 10min) ──
// Detecta totalLive >= LIVE_STORM_THRESHOLD (default 15) e alerta admin pra tomar ciência.
// Anti-spam: DM apenas no flip into-storm e flip out-of-storm. Cooldown 30min entre flips.
let _liveStormActive = false;
let _lastLiveStormDM = 0;
const LIVE_STORM_DM_COOLDOWN_MS = 30 * 60 * 1000;

// Quais sports mantêm polling rápido durante storm. Outros aplicam multiplicador
// de cooldown (LIVE_STORM_SLOW_FACTOR, default 3x) pra liberar CPU.
// ENV LIVE_STORM_FAST_POLL_SPORTS="dota,lol" (CSV, case-insensitive).
function _stormFastPollSet() {
  const raw = String(process.env.LIVE_STORM_FAST_POLL_SPORTS || 'dota,lol').toLowerCase();
  return new Set(raw.split(',').map(s => s.trim()).filter(Boolean));
}
function _liveStormCooldownMult(sport) {
  if (!_liveStormActive) return 1;
  const fast = _stormFastPollSet();
  if (fast.has(String(sport || '').toLowerCase())) return 1;
  const mult = parseFloat(process.env.LIVE_STORM_SLOW_FACTOR || '3');
  return Number.isFinite(mult) && mult > 1 ? mult : 3;
}

async function runLiveStormCycle() {
  if (!ADMIN_IDS.size) return;
  let result = null;
  try {
    const ext = require('./lib/agents-extended');
    result = await ext.runLiveStormManager(`http://127.0.0.1:${process.env.PORT || 8080}`);
  } catch (e) {
    log('WARN', 'LIVE-STORM', `falhou: ${e.message}`);
    return;
  }
  if (!result?.ok) return;

  const wasActive = _liveStormActive;
  _liveStormActive = !!result.storm_active;

  // DM silencioso por default — só envia se ENV opt-in. Logs continuam.
  // Ativar com LIVE_STORM_DM_ENABLED=true.
  const stormDmEnabled = /^(1|true|yes)$/i.test(String(process.env.LIVE_STORM_DM_ENABLED || ''));

  // Storm INICIOU
  if (_liveStormActive && !wasActive) {
    log('WARN', 'LIVE-STORM', `STORM ATIVO: ${result.live_total} partidas live (threshold ${result.storm_threshold})`);
    if (stormDmEnabled && Date.now() - _lastLiveStormDM > LIVE_STORM_DM_COOLDOWN_MS) {
      _lastLiveStormDM = Date.now();
      const tokenForAlert = resolveAlertsToken();
      if (tokenForAlert) {
        const sportsLine = Object.entries(result.by_sport || {}).sort((a, b) => b[1] - a[1])
          .map(([s, n]) => `*${s}*: ${n}`).join(' | ');
        const recsLine = (result.recommendations || []).slice(0, 3).map(r => `• ${r}`).join('\n');
        const msg = `⚡ *LIVE STORM ATIVO*\n\n` +
          `Total: *${result.live_total}* partidas live (threshold ${result.storm_threshold})\n\n` +
          `Por sport:\n${sportsLine}\n\n` +
          `Recomendações:\n${recsLine}\n\n` +
          `_Vou avisar quando voltar ao normal. Cooldown 30min._`;
        for (const adminId of ADMIN_IDS) await sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
      }
    }
  }

  // Storm RESOLVEU
  if (!_liveStormActive && wasActive) {
    log('INFO', 'LIVE-STORM', `Storm resolvido: ${result.live_total} live (abaixo do threshold)`);
    if (stormDmEnabled) {
      const tokenForAlert = resolveAlertsToken();
      if (tokenForAlert) {
        const msg = `✅ *LIVE STORM RESOLVIDO*\n\n` +
          `Voltou ao volume normal: *${result.live_total}* partidas live.\n` +
          `Sistema operando em capacidade padrão.`;
        for (const adminId of ADMIN_IDS) await sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
      }
    }
  }

  // Log silencioso quando estável
  if (_liveStormActive === wasActive) {
    log('DEBUG', 'LIVE-STORM', `Ciclo: ${result.live_total} live | storm ${_liveStormActive ? 'ON' : 'OFF'}`);
  }
}

// ── LoL Model Freshness Check (1x/dia) ──
// Compara lol-weights.json trainedAt vs patches/splits/idade em oracleselixir_games.
// DMs admin em nível attention/retrain-now. Fresh = log debug only.
async function runLolFreshnessCycle() {
  if (!ADMIN_IDS.size) return;
  const { exec } = require('child_process');
  const scriptPath = require('path').join(__dirname, 'scripts', 'check-model-freshness.js');
  exec(`node "${scriptPath}" --json`, { timeout: 30000 }, (err, stdout) => {
    if (err && err.code !== 1 && err.code !== 2) {
      log('WARN', 'FRESHNESS', `exec err: ${err.message}`);
      return;
    }
    let r;
    try { r = JSON.parse(stdout); } catch (e) { log('WARN', 'FRESHNESS', `parse err: ${e.message}`); return; }
    if (r.level === 'fresh') {
      log('DEBUG', 'FRESHNESS', `LoL model fresh (age=${r.ageDays}d)`);
      return;
    }
    log(r.level === 'retrain-now' ? 'WARN' : 'INFO', 'FRESHNESS',
      `LoL ${r.level}: ${(r.reasons || []).join(' | ')}`);
    const tokenForAlert = resolveAlertsToken();
    if (!tokenForAlert) return;
    const emoji = r.level === 'retrain-now' ? '🔴' : '🟡';
    const msg = `${emoji} *Modelo LoL ${r.level.toUpperCase()}*\n\n` +
      `Idade: ${r.ageDays}d | Treinado em: ${(r.trainedAtIso || '').slice(0, 16)}\n\n` +
      `Razões:\n${(r.reasons || []).map(x => `• ${x}`).join('\n')}\n\n` +
      (r.newPatches?.length
        ? `Patches novos: ${r.newPatches.map(p => p.patch).join(', ')}\n\n`
        : '') +
      `_${(r.recommendation || '').slice(0, 400)}_`;
    if (!_isCycleMuted('lol-freshness')) for (const adminId of ADMIN_IDS) sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));

    // Auto-trigger isotonic refresh quando retrain-now.
    // Evita reactivar múltiplas vezes: usa flag global + cooldown 24h.
    if (r.level === 'retrain-now' && process.env.AUTO_ISOTONIC_REFRESH !== 'false') {
      if (!global.__lastIsotonicRefresh || (Date.now() - global.__lastIsotonicRefresh) > 24 * 60 * 60 * 1000) {
        global.__lastIsotonicRefresh = Date.now();
        runIsotonicRefreshAsync(tokenForAlert);
      }
    }
  });
}

// Isotonic refresh async: roda scripts/refresh-all-isotonics.js em background.
// DM admin com summary no fim. Trigger manual via /admin ou auto via freshness retrain-now.
async function runIsotonicRefreshAsync(token) {
  const { exec } = require('child_process');
  const scriptPath = require('path').join(__dirname, 'scripts', 'refresh-all-isotonics.js');
  log('INFO', 'ISOTONIC-REFRESH', 'Iniciando refresh automático (auto-trigger freshness)...');
  exec(`node "${scriptPath}" --retrain --sync --json`, { timeout: 10 * 60 * 1000 }, (err, stdout) => {
    let r;
    try { r = JSON.parse(stdout); } catch { r = null; }
    if (err || !r) {
      log('ERROR', 'ISOTONIC-REFRESH', `falhou: ${err?.message || 'parse err'}`);
      return;
    }
    const allOk = r.jobs.every(j => j.ok);
    const rollbackCount = (r.rollbacks || []).filter(rb => !rb.error).length;
    log(allOk ? 'INFO' : 'WARN', 'ISOTONIC-REFRESH',
      `Concluído em ${Math.round(r.jobs.reduce((a,j) => a + j.durSec, 0))}s | ${r.jobs.filter(j=>j.ok).length}/${r.jobs.length} OK | changes: ${r.changes?.length || 0}${rollbackCount ? ` | rollbacks: ${rollbackCount}` : ''}`);
    if (!token) return;
    const emoji = rollbackCount > 0 ? '↺' : (allOk ? '✅' : '⚠️');
    const jobSummary = r.jobs.map(j => `${j.ok ? '✓' : '✗'} ${j.label}`).join('\n');
    const changesSummary = (r.changes || []).slice(0, 10).map(c => `• ${c}`).join('\n') || '_nada mudou_';
    let rollbackSection = '';
    if (r.rollbacks?.length) {
      rollbackSection = '\n\n*Rollbacks (regressão detectada):*\n' +
        r.rollbacks.map(rb => rb.error
          ? `✗ ${rb.file}: ${rb.error}`
          : `↺ ${rb.file} revertido (Brier piorou ${rb.reasonPct}%)`
        ).join('\n');
    }
    const msg = `${emoji} *Refresh automático de modelos concluído*\n\n` +
      `Jobs:\n${jobSummary}\n\n` +
      `Changes:\n${changesSummary}${rollbackSection}`;
    for (const adminId of ADMIN_IDS) sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
  });
}

// ── Market Tip Readiness Check (1x/dia) ──
// Query shadow stats: se (sport, market) atinge N≥30 settled AND ROI>=threshold, DM admin
// sugerindo ativação. Anti-spam: só notifica 1x por combination.
const _marketTipReadyAlerted = new Set(); // key: sport|market — evita re-alert
async function runMarketTipReadinessCheck() {
  if (!ADMIN_IDS.size) return;
  let stats;
  try {
    const { getShadowStats } = require('./lib/market-tips-shadow');
    stats = getShadowStats(db, { days: 60 });
  } catch (e) {
    log('DEBUG', 'MT-READY', `stats err: ${e.message}`);
    return;
  }
  if (!Array.isArray(stats) || !stats.length) return;

  const MIN_SETTLED = parseInt(process.env.MT_READY_MIN_SETTLED || '30', 10);
  const MIN_ROI = parseFloat(process.env.MT_READY_MIN_ROI || '5');
  const MIN_CLV = parseFloat(process.env.MT_READY_MIN_CLV || '0');
  const MIN_CLV_N = parseInt(process.env.MT_READY_MIN_CLV_N || '10', 10);

  const ready = [];
  const blockedByClv = [];
  for (const s of stats) {
    if (s.settled < MIN_SETTLED) continue;
    if (s.roiPct == null || s.roiPct < MIN_ROI) continue;
    const k = `${s.sport}|${s.market}`;
    if (_marketTipReadyAlerted.has(k)) continue;
    // Evita alertar pra segments já ativos via ENV.
    const envKey = `${s.sport.toUpperCase()}_MARKET_TIPS_ENABLED`;
    if (process.env[envKey] === 'true') continue;
    // CLV guard: se temos sample suficiente (≥MIN_CLV_N) e CLV < threshold,
    // a ROI positiva provavelmente é variance — NÃO alerta. Admin ainda pode forçar.
    if (s.clvN >= MIN_CLV_N && s.avgClv != null && s.avgClv < MIN_CLV) {
      blockedByClv.push(s);
      continue;
    }
    ready.push(s);
  }

  if (blockedByClv.length) {
    log('INFO', 'MT-READY', `${blockedByClv.length} segments ROI-ok mas CLV<${MIN_CLV}% — skipped (variance-driven)`);
  }
  if (!ready.length) return;

  const tokenForAlert = resolveAlertsToken();
  if (!tokenForAlert) return;

  const lines = ready.map(s => {
    const clvStr = s.clvN > 0
      ? ` CLV=${s.avgClv >= 0 ? '+' : ''}${s.avgClv.toFixed(1)}% (n=${s.clvN})`
      : ' CLV=?';
    return `• *${s.sport}/${s.market}*: n=${s.n} settled=${s.settled} hitRate=${s.hitRate}% ROI=*+${s.roiPct.toFixed(1)}%* avgEv=${s.avgEv.toFixed(1)}%${clvStr}`;
  }).join('\n');

  const envFlags = [...new Set(ready.map(s => s.sport))].map(sp => `${sp.toUpperCase()}_MARKET_TIPS_ENABLED=true`).join(' && ');

  const msg = `🎯 *MARKET TIPS — PRONTOS PRA ATIVAR*\n\n` +
    `Após shadow log acumulado, estes segments bateram o threshold ` +
    `(N≥${MIN_SETTLED} settled, ROI≥${MIN_ROI}%, CLV≥${MIN_CLV}% se n_clv≥${MIN_CLV_N}):\n\n${lines}\n\n` +
    `Pra ativar admin-DM:\n\`${envFlags}\` no .env + restart\n\n` +
    `_Shadow continuará logando. Você só liga o DM._`;

  if (!_isCycleMuted('mt-readiness')) for (const adminId of ADMIN_IDS) await sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
  for (const s of ready) _marketTipReadyAlerted.add(`${s.sport}|${s.market}`);
  log('INFO', 'MT-READY', `DM admin: ${ready.length} segments prontos pra ativar`);
}

// ── Market tips LEAK guard ──
// Simétrico ao readiness: shadow CLV<cutoff + n≥cutoff → auto-desativa DM market-tip
// real daquele (sport, market). Persiste em market_tips_runtime_state. Auto-restaura
// quando CLV recupera ≥CLV_RESTORE.
const _marketTipsDisabledRuntime = new Map(); // Map<'sport|market', { reason, since, clv, n, source }>

function _loadMarketTipsRuntimeState() {
  try {
    // Migrations progressivas: 050 base · 051 add side · 063 add league.
    // Best-effort cascading downgrade se schema antigo.
    let rows;
    try {
      rows = db.prepare(`SELECT sport, market, side, league, source, reason, clv_pct, clv_n, updated_at FROM market_tips_runtime_state WHERE disabled = 1`).all();
    } catch (_) {
      try {
        rows = db.prepare(`SELECT sport, market, side, source, reason, clv_pct, clv_n, updated_at FROM market_tips_runtime_state WHERE disabled = 1`).all().map(r => ({ ...r, league: null }));
      } catch (__) {
        rows = db.prepare(`SELECT sport, market, source, reason, clv_pct, clv_n, updated_at FROM market_tips_runtime_state WHERE disabled = 1`).all().map(r => ({ ...r, side: null, league: null }));
      }
    }
    _marketTipsDisabledRuntime.clear();
    for (const r of rows) {
      const parts = [r.sport, r.market];
      if (r.side) parts.push(r.side);
      if (r.league) parts.push(r.league);
      const key = parts.join('|');
      _marketTipsDisabledRuntime.set(key, {
        reason: r.reason, since: r.updated_at, clv: r.clv_pct, n: r.clv_n, source: r.source,
        side: r.side || null,
        league: r.league || null,
      });
    }
    if (_marketTipsDisabledRuntime.size) log('INFO', 'MT-GUARD', `Loaded ${_marketTipsDisabledRuntime.size} runtime disables`);
  } catch (e) { log('DEBUG', 'MT-GUARD', `load err: ${e.message}`); }
}

// Promove tip MT pra `tips` (regular)? Apenas quando env `<SPORT>_MARKET_TIPS_ENABLED=true`.
// Diferente de `isMarketTipsEnabled` que pode retornar true só pra DM (via
// MT_SHADOW_DM_ALL) sem promover — promoção é mais estrita.
function isMarketTipsPromoteEnabled(sport) {
  const up = String(sport).toUpperCase();
  const aliasEnv = { DOTA2: 'DOTA', CS2: 'CS' }[up];
  return process.env[`${up}_MARKET_TIPS_ENABLED`] === 'true'
    || (aliasEnv && process.env[`${aliasEnv}_MARKET_TIPS_ENABLED`] === 'true');
}

// 2026-04-28: per-market EV gate genérico. Sport pode definir gates diferentes
// por tipo de mercado (ex: handicap calibrado bem, total leak). Tennis já usa
// padrão similar (TENNIS_TG_MIN_EV, _HG_MIN_EV) — esta função generaliza.
// Usage: const minEv = perMarketEvGate(sport, t.market, defaultMinEv);
function perMarketEvGate(sport, market, defaultEv) {
  const sp = String(sport).toUpperCase().replace(/[^A-Z0-9]/g, '');
  const mk = String(market || '').toUpperCase().replace(/[^A-Z0-9_]/g, '');
  // Mapping de aliases comuns pra envs curtas
  const shortKey = mk === 'HANDICAP' ? 'HC'
    : mk === 'HANDICAPSETS' ? 'HS'
    : mk === 'HANDICAPGAMES' ? 'HG'
    : mk === 'TOTAL' ? 'TT'
    : mk === 'TOTALGAMES' ? 'TG'
    : mk === 'TOTALACES' ? 'TA'
    : /^TOTAL_KILLS_MAP\d+$/.test(mk) ? 'TK'
    : null;
  // Tenta env por short key (ex: LOL_MT_HC_MIN_EV) e fallback long key (LOL_MT_HANDICAP_MIN_EV)
  const candidates = [
    shortKey ? `${sp}_MT_${shortKey}_MIN_EV` : null,
    `${sp}_MT_${mk}_MIN_EV`,
  ].filter(Boolean);
  for (const k of candidates) {
    const v = parseFloat(process.env[k]);
    if (Number.isFinite(v) && v >= 0) return v;
  }
  return defaultEv;
}

// MT_PERMANENT_DISABLE_LIST — env-driven blocklist permanente, csv com
// `sport|market` ou `sport|market|side` (case-sensitive na parte do market).
// Aplica-se ANTES do runtime guard, sem precisar persistir em DB.
// Ex: MT_PERMANENT_DISABLE_LIST=tennis|totalGames|over,lol|total_kills_map3
// Default inclui leak conhecido (audit prod 2026-04-30): tennis totalGames over.
let _MT_PERMANENT_DISABLE = null;
function _getMtPermanentDisable() {
  if (_MT_PERMANENT_DISABLE !== null) return _MT_PERMANENT_DISABLE;
  // Default blocklist (audits prod 2026-04-30):
  //   tennis|totalGames|over: ROI -20.2% n=57 (sample sólido, leak persistente)
  //   lol|total:               ROI -54% n=10 (sample baixo mas magnitude clara)
  const raw = String(process.env.MT_PERMANENT_DISABLE_LIST ?? 'tennis|totalGames|over,lol|total').trim();
  _MT_PERMANENT_DISABLE = new Set();
  for (const entry of raw.split(',').map(s => s.trim()).filter(Boolean)) {
    _MT_PERMANENT_DISABLE.add(entry);
  }
  return _MT_PERMANENT_DISABLE;
}

function isMarketTipsEnabled(sport, market = null, side = null, league = null) {
  if (process.env.MARKET_TIPS_DM_KILL_SWITCH === 'true') return false;
  const up = String(sport).toUpperCase();
  // Aceita alias histórico: DOTA_* pra 'dota2', CS_* pra 'cs2'
  const aliasEnv = { DOTA2: 'DOTA', CS2: 'CS' }[up];
  const envEnabled = process.env[`${up}_MARKET_TIPS_ENABLED`] === 'true'
    || (aliasEnv && process.env[`${aliasEnv}_MARKET_TIPS_ENABLED`] === 'true');
  // MT_SHADOW_DM_ALL=true: força DM pra todos sports MT (mesmo sem promoção
  // ativa). Útil pra centralizar visibilidade de TODAS oportunidades MT em
  // um bot único antes de decidir promover. recordMarketTipAsRegular continua
  // gateado por isMarketTipsPromoteEnabled (só promove quando env explícito).
  const shadowDmAll = /^true$/i.test(process.env.MT_SHADOW_DM_ALL || '');
  const enabled = envEnabled || shadowDmAll;
  if (!enabled) return false;
  if (market) {
    // Permanent blocklist (env-driven, antes de runtime/DB checks).
    const perm = _getMtPermanentDisable();
    if (side && perm.has(`${sport}|${market}|${side}`)) return false;
    if (perm.has(`${sport}|${market}`)) return false;
    // Precedência runtime: (market+side+league) > (market+side) > market inteiro.
    // League é match completo (não normalize) — leak guard salva exato.
    if (side && league && _marketTipsDisabledRuntime.has(`${sport}|${market}|${side}|${league}`)) return false;
    if (side && _marketTipsDisabledRuntime.has(`${sport}|${market}|${side}`)) return false;
    if (_marketTipsDisabledRuntime.has(`${sport}|${market}`)) return false;
  }
  return true;
}

// Mapa market_type pro /record-tip (canônico maiúsculo). Mantém compat com o
// settle propagation em market-tips-shadow.js que reverte pro market original.
// 2026-04-28: espelhado em lib/mt-result-propagator.js MARKET_TYPE_MAP.
// Mantenha sincronizado pra que recordMarketTipAsRegular escreva e
// propagateMtResultToTips leia o mesmo market_type.
const _MT_MARKET_TYPE_MAP = {
  handicap: 'HANDICAP',
  handicapSets: 'HANDICAP_SETS',
  handicapGames: 'HANDICAP_GAMES',
  total: 'TOTAL',
  totals: 'TOTAL',
  totalGames: 'TOTAL_GAMES',
  tiebreakMatch: 'TIEBREAK',
  totalAces: 'TOTAL_ACES',
  draw: 'DRAW',
  doubleChance: 'DOUBLECHANCE',
  correctScore: 'CORRECTSCORE',
  duration: 'DURATION',
  mapWinner: 'MAPWINNER',
  firstBlood: 'FIRSTBLOOD',
};

// Resolve participant pra market tip (não-ML). Pra h2h side (team1/team2/home/away)
// inclui linha sinalizada (ex: "Alexander Zverev -3.5") pra dashboard mostrar
// qual handicap foi tippado sem precisar de coluna extra. Pra over/under/yes/no
// preserva label sintético com linha+unidade.
//
// IMPORTANT: scanners (odds-markets-scanner.js:97, tennis-market-scanner.js:167)
// JÁ EMITEM line na perspectiva do side — line=-3.5 + side=away significa
// "Zverev (away) cobre -3.5". NÃO inverter sinal aqui. Bug fix 2026-04-27:
// versão anterior flipava → double-inversão (line=-3.5 virava "+3.5" no label).
function _mtParticipant(match, tip) {
  const s = String(tip.side || '').toLowerCase();
  const fmtLine = (line) => {
    const n = Number(line);
    if (!Number.isFinite(n)) return '';
    return n >= 0 ? `+${n}` : `${n}`;
  };
  if (s === 'team1' || s === 'home' || s === 'h') {
    const ln = fmtLine(tip.line);
    return ln ? `${match.team1} ${ln}` : match.team1;
  }
  if (s === 'team2' || s === 'away' || s === 'a') {
    const ln = fmtLine(tip.line);
    return ln ? `${match.team2} ${ln}` : match.team2;
  }
  if (s === 'over' || s === 'under') {
    // 2026-04-28: total_kills_map<N> dropava o número do mapa no display.
    // Extrai mapN se presente + corrige unit (kills, não "maps").
    const mkt = String(tip.market || '');
    const killsMapMatch = mkt.match(/^total_kills_map(\d+)$/);
    if (killsMapMatch) {
      return `Mapa ${killsMapMatch[1]} ${s.toUpperCase()} ${tip.line ?? ''} kills`.trim();
    }
    const unit = mkt === 'totalGames' ? 'games'
               : mkt === 'totals' ? 'gols'
               : mkt === 'totalAces' ? 'aces' : 'maps';
    return `${s.toUpperCase()} ${tip.line ?? ''} ${unit}`.trim();
  }
  if (s === 'yes' || s === 'no') return s.toUpperCase();
  if (s === 'd') return 'EMPATE';
  return tip.label || `${tip.market} ${s}`;
}

// Grava market tip como tip "real" no DB via /record-tip — ativa quando o
// sport correspondente tem MT promovido (DM real, não shadow). Permite que o
// stake conte na exposição da banca, settlement propague pro bankroll, e a tip
// apareça na seção "Tips recentes" do dashboard.
//
// Synthetic match_id: ${match.id}::mt::${market}::${side} pra coexistir com
// tip ML do mesmo jogo (que usa match.id puro). Ambas as tips podem rodar em
// paralelo sem trigger do dedup match_id.
//
// Returns the tipId on success, null on error/skip.
async function recordMarketTipAsRegular({ sport, match, tip, stake, isLive }) {
  try {
    if (!sport || !match || !tip) return null;
    const matchIdBase = String(match.id || `mt_${sport}_${Date.now()}`);
    const marketKey = String(tip.market || 'unknown');
    const sideKey = String(tip.side || 'na');

    // ── Football: market divergence gate ──
    // Pra sport=football, se model diverge >MAX pp de Pinnacle closing
    // benchmark (H2H direto de football_data_csv), segura tip.
    // Sharp money discordando = sinal de model errado/dados velhos.
    // env: FB_DIVERGENCE_GATE=true (default true), FB_DIVERGENCE_MAX_PP=12
    //
    // Restringe a tips 1X2 (ML/draw): closing odds H/D/A do Pinnacle só
    // referem ao match winner. Comparar prob handicap/totals/btts com
    // pH/pD/pA é categoria errada — precisa do mercado correspondente
    // (que ainda não temos no benchmark). Skip silencioso pra outros markets.
    const _mktLowerFB = String(tip.market || '').toLowerCase();
    const _isFb1X2 = _mktLowerFB === 'ml' || _mktLowerFB === '1x2' || _mktLowerFB === 'draw';
    if (sport === 'football' && _isFb1X2 && !/^(0|false|no)$/i.test(String(process.env.FB_DIVERGENCE_GATE ?? 'true'))) {
      try {
        const { getClosingOddsBenchmark } = require('./lib/football-data-features');
        const market = getClosingOddsBenchmark(db, match.team1, match.team2);
        if (market && tip.pModel != null) {
          // Mapeia side da tip pra prob (1X2_H/A/D ou ML)
          const isHome = /^(1X2_H|H|home|1)$/i.test(String(tip.side || ''));
          const isAway = /^(1X2_A|A|away|2)$/i.test(String(tip.side || ''));
          const isDraw = /^(1X2_D|D|draw|X|d)$/i.test(String(tip.side || ''));
          const marketSideP = isHome ? market.pH : isAway ? market.pA : isDraw ? market.pD : null;
          if (marketSideP != null) {
            const pp = Math.abs(tip.pModel - marketSideP) * 100;
            const maxPp = parseFloat(process.env.FB_DIVERGENCE_MAX_PP || '12');
            if (pp > maxPp) {
              log('WARN', 'FB-DIVERGENCE-GATE', `${match.team1} vs ${match.team2} ${tip.market}/${tip.side}: model=${(tip.pModel*100).toFixed(1)}% vs Pinn close=${(marketSideP*100).toFixed(1)}% (${pp.toFixed(1)}pp > ${maxPp}pp) — skip`);
              return null;
            }
          }
        }
      } catch (_) { /* opcional, não bloqueia */ }
    }

    // ── Sprint 1.1: Tournament exposure cap ──
    // Limita tips/torneio/dia pra evitar concentração (ATP Madrid: 78 tips em 7d).
    // env: MAX_TIPS_PER_TOURNAMENT_PER_DAY (default 8). 0 = disabled.
    const maxTtPerDay = parseInt(process.env.MAX_TIPS_PER_TOURNAMENT_PER_DAY || '8', 10);
    if (maxTtPerDay > 0 && match.league) {
      try {
        const cnt = db.prepare(`
          SELECT COUNT(*) AS n FROM tips
          WHERE sport = ? AND event_name = ?
            AND COALESCE(is_shadow,0) = 0
            AND COALESCE(archived,0) = 0
            AND date(sent_at) = date('now')
        `).get(sport, match.league);
        if (cnt && cnt.n >= maxTtPerDay) {
          log('INFO', 'MT-EXPOSURE-CAP', `${sport}/${match.league}: ${cnt.n}/${maxTtPerDay} tips hoje — skip ${tip.market}/${tip.side}`);
          return null;
        }
      } catch (_) {}
    }

    // ── Sprint 1.2: CLV pre-dispatch gate (velocity-based) ──
    // Se Pinnacle moveu >X% CONTRA o side da tip nos últimos Y min, segura
    // (sharp money entrou no lado oposto = tip provavelmente já stale).
    // env: CLV_PREDISPATCH_GATE=true (default true), CLV_PREDISPATCH_THRESHOLD=2.5
    const clvGateOn = !/^(0|false|no)$/i.test(String(process.env.CLV_PREDISPATCH_GATE ?? 'true'));
    if (clvGateOn) {
      try {
        const slDet = require('./lib/stale-line-detector');
        const vel = require('./lib/velocity-tracker');
        const threshold = parseFloat(process.env.CLV_PREDISPATCH_THRESHOLD || '2.5');
        const windowMinPrev = process.env.VELOCITY_WINDOW_MIN;
        process.env.VELOCITY_WINDOW_MIN = process.env.CLV_PREDISPATCH_WINDOW_MIN || '10';
        const evt = vel.checkVelocity(slDet._ringBuf, {
          sport, team1: match.team1, team2: match.team2, side: tip.side,
        });
        if (windowMinPrev !== undefined) process.env.VELOCITY_WINDOW_MIN = windowMinPrev;
        else delete process.env.VELOCITY_WINDOW_MIN;
        // velocityPct < 0 = odd CAIU = side virou favorito = sharp comprou esse lado
        // velocityPct > 0 = odd SUBIU = sharp vendeu = nosso side está virando azarão
        // Bloqueia quando odd subiu acima do threshold (=mercado discordando da tip).
        if (evt && evt.velocityPct >= threshold) {
          log('WARN', 'MT-CLV-GATE', `${sport}/${marketKey}/${sideKey} ${match.team1} vs ${match.team2}: Pinnacle ${tip.side} odd subiu ${evt.velocityPct.toFixed(1)}% em ${evt.windowMin}min (${evt.oldOdd}→${evt.newOdd}) — skip dispatch`);
          return null;
        }
      } catch (_) { /* velocity opcional */ }
    }

    // Encode line no match_id pra eliminar line-mismatch no propagator. Format:
    // `${base}::mt::${market}::${side}::ln<line_sanitized>` (e.g., ::lnN3.5 pra -3.5,
    // ::lnP4.5 pra +4.5, ::ln21.5 pra over/under). Propagator extrai e valida.
    // ML/draw sem line: omite suffix ::ln (compat com tips legacy).
    let lineSuffix = '';
    if (Number.isFinite(tip.line)) {
      const ln = Number(tip.line);
      const tag = ln < 0 ? `N${Math.abs(ln)}` : ln > 0 ? `P${ln}` : '0';
      lineSuffix = `::ln${tag}`;
    }
    const syntheticMatchId = `${matchIdBase}::mt::${marketKey}::${sideKey}${lineSuffix}`;
    const market_type = _MT_MARKET_TYPE_MAP[marketKey] || marketKey.toUpperCase();
    const participant = _mtParticipant(match, tip);

    // ── Sprint 3.1: Bayesian league trust score ──
    // Multiplica stake_raw × trust(0.15..1.20) baseado em ROI rolling 60d da
    // (sport, liga, market). Liga "morna" recebe stake reduzido sem block total.
    let stakeAdjusted = stake;
    let trustInfo = null;
    try {
      const { applyTrustToStake } = require('./lib/league-trust');
      const stakeNum = typeof stake === 'number' ? stake : parseFloat(String(stake || '1').replace('u','')) || 1;
      const t = applyTrustToStake(db, sport, match.league, market_type, stakeNum);
      if (t.applied) {
        log('INFO', 'LEAGUE-TRUST', `${sport}/${match.league}/${market_type}: trust=${t.trust} (n=${t.info.n} ROI=${t.info.roi}% src=${t.info.source}) stake ${stakeNum}u → ${t.stakeFinal}u`);
        // Floor 0.1u — stakes < 0.1u não valem dispatch (custo fixo > EV).
        if (t.stakeFinal < 0.1) {
          log('INFO', 'LEAGUE-TRUST', `${sport}/${match.league}/${market_type}: stake_final ${t.stakeFinal}u < 0.1u floor — skip dispatch`);
          return null;
        }
        stakeAdjusted = t.stakeFinal;
      }
      trustInfo = t.info;
    } catch (e) { log('DEBUG', 'LEAGUE-TRUST', `err: ${e.message}`); }

    const stakeStr = typeof stakeAdjusted === 'number' ? `${stakeAdjusted}u` : String(stakeAdjusted || '1u');
    const conf = tip.ev >= 15 ? 'ALTA' : tip.ev >= 8 ? 'MÉDIA' : 'BAIXA';
    const rec = await serverPost('/record-tip', {
      matchId: syntheticMatchId,
      eventName: match.league || sport,
      p1: match.team1, p2: match.team2,
      tipParticipant: participant,
      odds: tip.odd,
      ev: tip.ev,
      stake: stakeStr,
      confidence: conf,
      isLive: !!isLive,
      market_type,
      modelP1: tip.pModelHome ?? null,
      modelP2: tip.pModelAway ?? null,
      modelPPick: tip.pModel ?? null,
      modelLabel: tip.label || null,
      tipReason: `MT scanner ${tip.label || tip.market}/${tip.side}`,
      sport,
      isShadow: 0,
      // Meta extra pra debugging/audit
      mtSourceMarket: marketKey,
      mtSourceSide: sideKey,
      mtSourceLine: tip.line ?? null,
      // tip_context_json fields:
      factors: [{ label: 'MT', value: `${tip.market}/${tip.side}${tip.line != null ? ` line=${tip.line}` : ''}` }],
      stakeAdjust: Number.isFinite(tip.stakeAdjust) ? tip.stakeAdjust : null,
      pickSide: tip.side || null,
    }, sport).catch(e => { log('WARN', 'MT-RECORD', `serverPost err: ${e.message}`); return null; });
    if (!rec) return null;
    if (rec.skipped) {
      log('INFO', 'MT-RECORD', `${sport}/${marketKey}/${sideKey} skipped (${rec.reason})`);
      return null;
    }
    if (rec.tipId) {
      log('INFO', 'MT-RECORD', `${sport}/${marketKey}/${sideKey} → tip id=${rec.tipId} stake=${stakeStr}`);
      return rec.tipId;
    }
    return null;
  } catch (e) {
    log('WARN', 'MT-RECORD', `err: ${e.message}`);
    return null;
  }
}

// Side-level ROI auto-guard — complementa o CLV guard por agregação em
// (sport, market, side). Roda no mesmo cron do runMarketTipsLeakGuard (1h).
// Usa ROI direto porque shadow tips têm resultado final (win/loss) → sinal
// mais direto que CLV. Cutoff e janela configuráveis via env.
// LoL kills model calibration check — rodado 1x/dia.
// Lê via /admin/kills-calibration → log + DM admin se degraded.
async function runKillsCalibrationCheck() {
  if (/^(0|false|no)$/i.test(String(process.env.KILLS_CALIB_AUTO ?? 'true'))) return;
  const targetHour = parseInt(process.env.KILLS_CALIB_HOUR || '3', 10) || 3;
  const now = new Date();
  if (now.getHours() !== targetHour) return;
  // Já rodou hoje? (cache simples no module scope)
  const today = now.toISOString().slice(0, 10);
  if (runKillsCalibrationCheck._lastRunDay === today) return;
  runKillsCalibrationCheck._lastRunDay = today;
  try {
    const adminKey = (process.env.ADMIN_KEY || '').trim();
    if (!adminKey) { log('DEBUG', 'KILLS-CALIB', 'sem ADMIN_KEY — skip'); return; }
    const days = parseInt(process.env.KILLS_CALIB_DAYS || '14', 10) || 14;
    const r = await serverGet(`/admin/kills-calibration?days=${days}`, null, { 'x-admin-key': adminKey })
      .catch(e => ({ error: e.message }));
    if (r?.error) { log('WARN', 'KILLS-CALIB', `endpoint err: ${r.error}`); return; }
    if (!r?.calib?.overall) { log('INFO', 'KILLS-CALIB', `n=${r?.calib?.n || 0} insufficient sample`); return; }
    const o = r.calib.overall;
    const dec = r.decision || {};
    const msg = `LoL kills calib (${days}d): n=${o.n} brier=${o.brier} ece=${r.calib.byBucket ? '✓' : '?'} mae=${o.mae} hit=${(o.hit_rate*100).toFixed(1)}% ROI=${o.roi_pct}% → ${dec.action || 'unknown'}`;
    log(dec.action === 'disable_recommended' ? 'WARN' : 'INFO', 'KILLS-CALIB', msg);
    if (dec.action === 'disable_recommended') {
      const dmText = `⚠️ *Kills Model Calib Degraded*\n\n${msg}\n\nThresholds: brier>${dec.threshold.brier}, mae>${dec.threshold.mae}\n\nRecomendo desativar com \`LOL_MARKET_SCAN=false\` ou recalibrar.`;
      try { await sendAdminDMs(resolveAlertsToken(), dmText, { parse_mode: 'Markdown' }, 'kills-calib'); }
      catch (_) {}
    }
  } catch (e) { log('ERROR', 'KILLS-CALIB', e.message); }
}

// LoL cross-source kill validation — rodado 1x/dia.
async function runLolCrossCheckDaily() {
  if (/^(0|false|no)$/i.test(String(process.env.LOL_XCHECK_AUTO ?? 'true'))) return;
  const targetHour = parseInt(process.env.LOL_XCHECK_HOUR || '4', 10) || 4;
  const now = new Date();
  if (now.getHours() !== targetHour) return;
  const today = now.toISOString().slice(0, 10);
  if (runLolCrossCheckDaily._lastRunDay === today) return;
  runLolCrossCheckDaily._lastRunDay = today;
  try {
    const adminKey = (process.env.ADMIN_KEY || '').trim();
    if (!adminKey) return;
    const r = await serverGet(`/admin/lol-xcheck?days=14&run=1`, null, { 'x-admin-key': adminKey })
      .catch(e => ({ error: e.message }));
    if (r?.error) { log('WARN', 'LOL-XCHECK', `endpoint err: ${r.error}`); return; }
    const rr = r?.runResult;
    if (!rr) return;
    const msg = `LoL cross-source check: ${rr.n} games, ${rr.flagged} flagged disagreement`;
    log(rr.flagged > 0 ? 'WARN' : 'INFO', 'LOL-XCHECK', msg);
    if (rr.flagged >= parseInt(process.env.LOL_XCHECK_DM_THRESHOLD || '5', 10)) {
      const samples = (rr.results || []).slice(0, 5).map(s => `• ${s.teams} spread=${s.spread} (${JSON.stringify(s.sources)})`).join('\n');
      const dmText = `⚠️ *LoL Source Disagreement*\n\n${msg}\n\nSamples:\n${samples}\n\nReview \`lol_source_disagreement\` table.`;
      try { await sendAdminDMs(resolveAlertsToken(), dmText, { parse_mode: 'Markdown' }, 'lol-xcheck'); } catch (_) {}
    }
  } catch (e) { log('ERROR', 'LOL-XCHECK', e.message); }
}

async function runMarketTipsRoiGuardSided() {
  if (/^(0|false|no)$/i.test(String(process.env.MT_ROI_GUARD_AUTO ?? 'true'))) return;
  if (!ADMIN_IDS.size) return;
  // 2026-04-29 Sprint 1.3: gates relaxados pra detecção mais rápida
  // (Saint Malo -56% n=8 passou batido com n_min=30; agora bloqueia em n=10).
  const ROI_CUTOFF = parseFloat(process.env.MT_ROI_GUARD_CUTOFF || '-8');
  const N_CUTOFF = parseInt(process.env.MT_ROI_GUARD_N_MIN || '10', 10);
  const ROI_RESTORE = parseFloat(process.env.MT_ROI_GUARD_RESTORE || '3');
  const WINDOW_DAYS = parseInt(process.env.MT_ROI_GUARD_WINDOW_DAYS || '14', 10);

  let rows;
  try {
    rows = db.prepare(`
      SELECT sport, market, side,
        COUNT(*) AS n_settled,
        SUM(CASE WHEN result = 'win' THEN 1 ELSE 0 END) AS wins,
        SUM(CASE WHEN result = 'win' THEN COALESCE(stake_units, 1) * (odd - 1) ELSE 0 END)
        - SUM(CASE WHEN result = 'loss' THEN COALESCE(stake_units, 1) ELSE 0 END) AS profit_u,
        SUM(CASE WHEN result IN ('win','loss') THEN COALESCE(stake_units, 1) ELSE 0 END) AS stake_u
      FROM market_tips_shadow
      WHERE result IN ('win', 'loss')
        AND created_at >= datetime('now', '-' || ? || ' days')
        AND side IS NOT NULL
      GROUP BY sport, market, side
      HAVING n_settled >= ?
    `).all(WINDOW_DAYS, N_CUTOFF);
  } catch (e) { log('DEBUG', 'MT-ROI-GUARD', `query err: ${e.message}`); return; }

  const disabled = [], restored = [];
  const ts = new Date().toISOString();

  for (const s of rows) {
    const roiPct = s.stake_u > 0 ? (s.profit_u / s.stake_u) * 100 : 0;
    const key = `${s.sport}|${s.market}|${s.side}`;
    const wasDisabled = _marketTipsDisabledRuntime.has(key);

    if (!wasDisabled && roiPct <= ROI_CUTOFF) {
      const reason = `ROI ${roiPct.toFixed(1)}% n=${s.n_settled} hit=${(s.wins/s.n_settled*100).toFixed(0)}%`;
      try {
        db.prepare(`INSERT OR REPLACE INTO market_tips_runtime_state
          (sport, market, side, disabled, source, reason, roi_pct, updated_at)
          VALUES (?, ?, ?, 1, 'auto_roi_leak', ?, ?, ?)`).run(
          s.sport, s.market, s.side, reason, +roiPct.toFixed(2), ts
        );
        _marketTipsDisabledRuntime.set(key, { reason, since: ts, roi: roiPct, n: s.n_settled, source: 'auto_roi_leak', side: s.side });
        disabled.push(`🚫 ${s.sport}/${s.market}/${s.side} — ${reason}`);
        log('WARN', 'MT-ROI-GUARD', `auto-disabled ${key}: ${reason}`);
      } catch (e) { log('WARN', 'MT-ROI-GUARD', `disable err: ${e.message}`); }
    }
    else if (wasDisabled) {
      const meta = _marketTipsDisabledRuntime.get(key);
      if (meta?.source === 'auto_roi_leak' && roiPct >= ROI_RESTORE) {
        try {
          db.prepare(`DELETE FROM market_tips_runtime_state WHERE sport = ? AND market = ? AND side = ? AND source = 'auto_roi_leak'`).run(s.sport, s.market, s.side);
          _marketTipsDisabledRuntime.delete(key);
          restored.push(`✅ ${s.sport}/${s.market}/${s.side} — ROI recuperou pra ${roiPct.toFixed(1)}% (n=${s.n_settled})`);
          log('INFO', 'MT-ROI-GUARD', `auto-restored ${key}: ROI=${roiPct.toFixed(1)}%`);
        } catch (e) { log('WARN', 'MT-ROI-GUARD', `restore err: ${e.message}`); }
      }
    }
  }

  if (disabled.length || restored.length) {
    const token = resolveAlertsToken();
    if (token) {
      let msg = `🛡️ *MT ROI GUARD — auto-tune*\n\nJanela ${WINDOW_DAYS}d, ROI cutoff ${ROI_CUTOFF}% (restore ≥${ROI_RESTORE}%), n≥${N_CUTOFF}.\n\n`;
      if (disabled.length) msg += `*Desabilitados:*\n${disabled.join('\n')}\n\n`;
      if (restored.length) msg += `*Restaurados:*\n${restored.join('\n')}`;
      if (!_isCycleMuted('mt-roi-guard')) for (const adminId of ADMIN_IDS) sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
  }
}

async function runMarketTipsLeakGuard() {
  if (/^(0|false|no)$/i.test(String(process.env.MT_LEAK_GUARD_AUTO || ''))) return;
  if (!ADMIN_IDS.size) return;
  const CLV_CUTOFF = parseFloat(process.env.MT_LEAK_CLV_CUTOFF || '-2');
  const N_CUTOFF = parseInt(process.env.MT_LEAK_N_CUTOFF || '30', 10);
  // Side-level pode usar n menor (granularidade fina). Default = max(N_CUTOFF/2, 15).
  const N_CUTOFF_SIDE = parseInt(process.env.MT_LEAK_N_CUTOFF_SIDE || String(Math.max(15, Math.floor(N_CUTOFF / 2))), 10);
  // League-level: granularidade ainda mais fina, requer n menor pra detectar leak antes
  // que cause prejuízo grande. Default 10. Cutoff CLV mais agressivo (default = CLV_CUTOFF)
  // pra evitar block prematuro em sample apertado.
  const N_CUTOFF_LEAGUE = parseInt(process.env.MT_LEAK_N_CUTOFF_LEAGUE || '10', 10);
  const CLV_RESTORE = parseFloat(process.env.MT_LEAK_CLV_RESTORE || '0');
  const SIDE_GUARD_DISABLED = /^(0|false|no)$/i.test(String(process.env.MT_LEAK_GUARD_SIDE_AUTO ?? 'true'));
  const LEAGUE_GUARD_DISABLED = /^(0|false|no)$/i.test(String(process.env.MT_LEAK_GUARD_LEAGUE_AUTO ?? 'true'));

  let statsMarket, statsBySide, statsByLeague;
  try {
    const { getShadowStats } = require('./lib/market-tips-shadow');
    statsMarket = getShadowStats(db, { days: 30 });
    statsBySide = SIDE_GUARD_DISABLED ? [] : getShadowStats(db, { days: 30, bySide: true });
    statsByLeague = LEAGUE_GUARD_DISABLED ? [] : getShadowStats(db, { days: 30, bySide: true, byLeague: true });
  } catch (_) { return; }
  if ((!Array.isArray(statsMarket) || !statsMarket.length) && !statsBySide.length && !statsByLeague.length) return;

  const disabled = [], restored = [];
  const ts = new Date().toISOString();

  // Helper compartilhado pra disable/restore. Granularidade decrescente:
  //   1. (sport, market)               — N_CUTOFF, mais conservador
  //   2. (sport, market, side)         — N_CUTOFF_SIDE
  //   3. (sport, market, side, league) — N_CUTOFF_LEAGUE, mais agressivo
  const processSegment = (s) => {
    const sideKey = s.side || null;
    const leagueKey = s.league || null;
    const parts = [s.sport, s.market];
    const labelParts = [s.sport, s.market];
    if (sideKey) { parts.push(sideKey); labelParts.push(sideKey); }
    if (leagueKey) { parts.push(leagueKey); labelParts.push(leagueKey); }
    const key = parts.join('|');
    const label = labelParts.join('/');
    const nThreshold = leagueKey ? N_CUTOFF_LEAGUE : (sideKey ? N_CUTOFF_SIDE : N_CUTOFF);
    const wasDisabled = _marketTipsDisabledRuntime.has(key);

    if (!wasDisabled && s.clvN >= nThreshold && s.avgClv != null && s.avgClv < CLV_CUTOFF) {
      const reason = `CLV ${s.avgClv.toFixed(1)}% n=${s.clvN} ROI=${s.roiPct != null ? s.roiPct.toFixed(1)+'%' : '?'}`;
      try {
        db.prepare(`INSERT OR REPLACE INTO market_tips_runtime_state
          (sport, market, side, league, disabled, source, reason, clv_pct, clv_n, roi_pct, updated_at)
          VALUES (?, ?, ?, ?, 1, 'auto_clv_leak', ?, ?, ?, ?, ?)`).run(
          s.sport, s.market, sideKey, leagueKey, reason, s.avgClv, s.clvN, s.roiPct, ts,
        );
        _marketTipsDisabledRuntime.set(key, { reason, since: ts, clv: s.avgClv, n: s.clvN, source: 'auto_clv_leak', side: sideKey, league: leagueKey });
        disabled.push(`🚫 ${label} — ${reason}`);
        log('WARN', 'MT-GUARD', `auto-disabled ${key}: ${reason}`);
      } catch (e) { log('WARN', 'MT-GUARD', `disable err: ${e.message}`); }
    }
    else if (wasDisabled) {
      const meta = _marketTipsDisabledRuntime.get(key);
      if (meta?.source === 'auto_clv_leak' && s.clvN >= nThreshold && s.avgClv != null && s.avgClv >= CLV_RESTORE) {
        try {
          // DELETE com null-safe match em side/league. Schema mantém NULL pra
          // segments market-level e side-level, valor explícito pra league-level.
          const sideCond = sideKey ? 'side = ?' : 'side IS NULL';
          const leagueCond = leagueKey ? 'league = ?' : 'league IS NULL';
          const stmtParams = [s.sport, s.market];
          if (sideKey) stmtParams.push(sideKey);
          if (leagueKey) stmtParams.push(leagueKey);
          db.prepare(`DELETE FROM market_tips_runtime_state WHERE sport = ? AND market = ? AND ${sideCond} AND ${leagueCond} AND source = 'auto_clv_leak'`).run(...stmtParams);
          _marketTipsDisabledRuntime.delete(key);
          restored.push(`✅ ${label} — CLV recuperou pra ${s.avgClv.toFixed(1)}% (n=${s.clvN})`);
          log('INFO', 'MT-GUARD', `auto-restored ${key}: CLV=${s.avgClv.toFixed(1)}%`);
        } catch (e) { log('WARN', 'MT-GUARD', `restore err: ${e.message}`); }
      }
    }
  };

  // Market-level (existente, n cutoff = N_CUTOFF)
  for (const s of statsMarket) processSegment(s);
  // Side-level (n cutoff = N_CUTOFF_SIDE menor pra granularidade fina)
  for (const s of statsBySide) {
    if (s.side) processSegment(s);
  }
  // League-level (n cutoff = N_CUTOFF_LEAGUE — mais agressivo pra detectar leak cedo)
  for (const s of statsByLeague) {
    if (s.side && s.league) processSegment(s);
  }

  if (disabled.length || restored.length) {
    const token = resolveAlertsToken();
    if (token) {
      const msg = `🛡️ *MT LEAK GUARD — 30d*\n\n${[...disabled, ...restored].join('\n')}\n\n_Market n≥${N_CUTOFF} · Side n≥${N_CUTOFF_SIDE} · League n≥${N_CUTOFF_LEAGUE} · CLV ≤ ${CLV_CUTOFF}%. Restaura em CLV ≥ ${CLV_RESTORE}%._`;
      if (!_isCycleMuted('mt-leak-guard')) for (const adminId of ADMIN_IDS) sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
  }
  log('INFO', 'MT-GUARD', `Ciclo OK — ${statsMarket.length} markets + ${statsBySide.length} sides + ${statsByLeague.length} leagues | ${disabled.length} disabled | ${restored.length} restored`);
}

// ── Weekly pipeline digest (1x/semana — 2ª feira 9h local) ──
let _lastWeeklyDigestDay = null;
async function runWeeklyPipelineDigest() {
  if (process.env.WEEKLY_DIGEST_ENABLED === 'false') return;
  if (!ADMIN_IDS.size) return;
  const now = new Date();
  if (now.getDay() !== 1 || now.getHours() !== 9) return; // 2ª feira 9h
  const today = now.toISOString().slice(0, 10);
  if (_lastWeeklyDigestDay === today) return;
  _lastWeeklyDigestDay = today;

  const token = resolveAlertsToken();
  if (!token) return;

  try {
    // Tips last 7d per sport
    const tipsBySport = db.prepare(`
      SELECT sport, COUNT(*) AS total,
        SUM(CASE WHEN result='win' THEN 1 ELSE 0 END) AS wins,
        SUM(CASE WHEN result='loss' THEN 1 ELSE 0 END) AS losses,
        SUM(CASE WHEN result IS NULL THEN 1 ELSE 0 END) AS pending,
        ROUND(SUM(COALESCE(profit_reais, 0)), 2) AS profit,
        ROUND(SUM(COALESCE(stake_reais, 0)), 2) AS staked
      FROM tips
      WHERE (archived IS NULL OR archived = 0)
        AND sent_at >= datetime('now','-7 days')
      GROUP BY sport ORDER BY total DESC
    `).all();

    // Banca delta
    const banca = db.prepare(`SELECT SUM(current_banca - initial_banca) AS delta FROM bankroll`).get();

    // Tasks executed (rejection + poll heartbeats últimos 7d seria ideal mas é in-memory)
    let msg = `📅 *WEEKLY DIGEST — ${today}*\n\n`;
    msg += `*💰 Banca total:* R$${(banca?.delta || 0).toFixed(2)} delta desde início\n\n`;
    msg += `*📊 Tips últimos 7d:*\n`;
    if (!tipsBySport.length) msg += `  _(sem tips na semana)_\n`;
    else {
      let totalProfit = 0, totalTips = 0, totalWins = 0, totalDecided = 0;
      for (const s of tipsBySport) {
        const decided = s.wins + s.losses;
        const roi = s.staked > 0 ? (s.profit / s.staked * 100).toFixed(1) : '?';
        const wr = decided > 0 ? (s.wins / decided * 100).toFixed(0) : '?';
        msg += `  · *${s.sport}*: ${s.total} tips (${s.wins}W/${s.losses}L/${s.pending}pending) ROI=${roi}% WR=${wr}% profit=${s.profit >= 0 ? '+' : ''}R$${s.profit.toFixed(2)}\n`;
        totalProfit += s.profit; totalTips += s.total; totalWins += s.wins; totalDecided += decided;
      }
      const globalROI = tipsBySport.reduce((a, s) => a + s.staked, 0);
      msg += `  *Total*: ${totalTips} tips | ROI=${globalROI > 0 ? (totalProfit/globalROI*100).toFixed(1) : '?'}% | profit=${totalProfit >= 0 ? '+' : ''}R$${totalProfit.toFixed(2)}\n\n`;
    }

    // Shadow tips
    try {
      const { getShadowStats } = require('./lib/market-tips-shadow');
      const stats = getShadowStats(db, { days: 7 });
      if (stats.length) {
        msg += `*📊 Shadow tips 7d (${stats.length} segments):*\n`;
        for (const s of stats.slice(0, 5)) {
          const hit = s.hitRate != null ? `${s.hitRate.toFixed(0)}%` : '?';
          const roi = s.roiPct != null ? `${s.roiPct >= 0 ? '+' : ''}${s.roiPct.toFixed(0)}%` : '?';
          const clv = s.avgClv != null ? `${s.avgClv >= 0 ? '+' : ''}${s.avgClv.toFixed(1)}%` : '?';
          msg += `  · ${s.sport}/${s.market}: n=${s.n} Hit=${hit} ROI=${roi} CLV=${clv}\n`;
        }
        msg += `\n`;
      }
    } catch (_) {}

    // Rejections summary 7d (só in-memory — pode ser parcial se bot reiniciou)
    const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000;
    const recentRej = _rejections.filter(r => r.ts >= cutoff);
    if (recentRej.length > 0) {
      const byReason = {};
      for (const r of recentRej) byReason[r.reason] = (byReason[r.reason] || 0) + 1;
      const top = Object.entries(byReason).sort((a, b) => b[1] - a[1]).slice(0, 3);
      msg += `*📋 Top rejection reasons (buffer in-memory):*\n`;
      for (const [r, n] of top) msg += `  · ${r}: ${n}\n`;
    }

    msg += `\n_Comandos:_ \`/pipeline-health\` · \`/alerts\` · \`/market-tips\``;

    for (const adminId of ADMIN_IDS) await sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    log('INFO', 'WEEKLY-DIGEST', `DM semanal: ${tipsBySport.length} sports`);
  } catch (e) { reportBug('WEEKLY-DIGEST', e); }
}

// ── Daily market-tips digest (1x/dia) ──
let _lastMtDigestDay = null;
async function runMarketTipsDigest() {
  if (process.env.MT_DIGEST_ENABLED === 'false') return;
  if (!ADMIN_IDS.size) return;
  const hour = parseInt(process.env.MT_DIGEST_HOUR || '8', 10);
  const now = new Date();
  if (now.getHours() !== hour) return;
  const today = now.toISOString().slice(0, 10);
  if (_lastMtDigestDay === today) return;
  _lastMtDigestDay = today;

  let stats7, stats30;
  try {
    const { getShadowStats } = require('./lib/market-tips-shadow');
    stats7 = getShadowStats(db, { days: 7 });
    stats30 = getShadowStats(db, { days: 30 });
  } catch (e) {
    log('DEBUG', 'MT-DIGEST', `stats err: ${e.message}`);
    return;
  }
  if (!Array.isArray(stats30) || !stats30.length) return;

  const token = resolveAlertsToken();
  if (!token) return;

  const fmt = (s) => {
    const hit = s.hitRate != null ? `${s.hitRate.toFixed(0)}%` : '-';
    const roi = s.roiPct != null ? `${s.roiPct >= 0 ? '+' : ''}${s.roiPct.toFixed(0)}%` : '-';
    const clv = s.avgClv != null ? `${s.avgClv >= 0 ? '+' : ''}${s.avgClv.toFixed(1)}%` : '-';
    return `${s.sport}/${s.market}: n=${s.n} Hit=${hit} ROI=${roi} CLV=${clv}`;
  };

  let msg = `📊 *MARKET TIPS DIGEST — ${today}*\n\n`;
  msg += `*Últimos 7d:*\n`;
  if (stats7.length) {
    msg += stats7.slice(0, 8).map(s => `• ${fmt(s)}`).join('\n') + '\n';
  } else {
    msg += `_sem tips nesta janela_\n`;
  }
  msg += `\n*Últimos 30d:*\n`;
  msg += stats30.slice(0, 8).map(s => `• ${fmt(s)}`).join('\n') + '\n';
  msg += `\n_Comando /market-tips pra detalhes. Readiness alert separado quando threshold bater._`;

  for (const adminId of ADMIN_IDS) await sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
  log('INFO', 'MT-DIGEST', `DM digest 7d=${stats7.length} 30d=${stats30.length}`);
}

// ── ML Shadow Digest (1x/dia) ──
// Cobre tips regulares com is_shadow=1 (sport experimental antes de ir live).
// Complementa runMarketTipsDigest (esse só cobre market_tips_shadow). Mesma
// hora default (8am) — pode personalizar via SHADOW_DIGEST_HOUR.
let _lastShadowDigestDay = null;
async function runMlShadowDigest() {
  if (/^(0|false|no)$/i.test(String(process.env.SHADOW_DIGEST_ENABLED ?? 'true')) === false &&
      process.env.SHADOW_DIGEST_ENABLED === 'false') return;
  if (!ADMIN_IDS.size) return;
  const hour = parseInt(process.env.SHADOW_DIGEST_HOUR || '8', 10);
  const now = new Date();
  if (now.getHours() !== hour) return;
  const today = now.toISOString().slice(0, 10);
  if (_lastShadowDigestDay === today) return;
  _lastShadowDigestDay = today;

  let r7, r30;
  try {
    r7 = await serverGet(`/shadow-summary?days=7`);
    r30 = await serverGet(`/shadow-summary?days=30`);
  } catch (e) {
    log('DEBUG', 'SHADOW-DIGEST', `summary err: ${e.message}`);
    return;
  }
  if (!r7?.ok || !r30?.ok) return;
  // Só envia se há tips ML shadow (não market) — esse digest é específico ML.
  if (!r30.regular?.length && !r7.regular?.length) return;

  const token = resolveAlertsToken();
  if (!token) return;

  const fmt = (v, suf = '') => v == null ? '?' : `${v >= 0 ? '+' : ''}${v}${suf}`;
  const roiEmoji = (roi) => roi == null ? '⚪' : roi >= 5 ? '✅' : roi <= -5 ? '❌' : '🟡';
  const fmtSport = (s) => {
    const hit = s.hit_rate != null ? `${s.hit_rate}%` : '?';
    const roi = s.roi_pct != null ? fmt(s.roi_pct, '%') : '?';
    const clv = s.clv_n > 0 ? ` CLV ${fmt(s.avg_clv, '%')}(n${s.clv_n})` : '';
    return `${roiEmoji(s.roi_pct)} *${s.sport}* n=${s.n} (${s.wins}W/${s.losses}L/${s.pending}P) Hit ${hit} ROI ${roi}${clv}`;
  };

  let msg = `🕶️ *ML SHADOW DIGEST — ${today}*\n\n`;
  msg += `*Últimos 7d:*\n`;
  if (r7.regular?.length) {
    msg += r7.regular.map(fmtSport).join('\n') + '\n';
  } else {
    msg += `_sem tips ML shadow nesta janela_\n`;
  }
  msg += `\n*Últimos 30d:*\n`;
  if (r30.regular?.length) {
    msg += r30.regular.map(fmtSport).join('\n') + '\n';
  } else {
    msg += `_sem tips_\n`;
  }
  msg += `\n_Critério graduação: n≥30, CLV+, ROI estável._`;
  msg += `\n_Cmds: /shadow [sport] · /shadow-summary [days]_`;

  for (const adminId of ADMIN_IDS) await sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
  log('INFO', 'SHADOW-DIGEST', `DM ML shadow 7d=${r7.regular?.length || 0} 30d=${r30.regular?.length || 0}`);
}

// ── Backtest Validator (1x/dia) ──
let _lastBacktestAlert = 0;
const _backtestMilestonesSeen = new Set();
async function runBacktestValidatorCycle() {
  if (_isCycleMuted('backtest-validator')) { return; }
  if (!ADMIN_IDS.size) return;
  let result = null;
  try {
    const ext = require('./lib/agents-extended');
    result = await ext.runBacktestValidator(db, { days: 90 });
  } catch (e) {
    log('WARN', 'BACKTEST-VALIDATOR', `falhou: ${e.message}`);
    return;
  }
  if (!result?.ok) return;
  log('INFO', 'BACKTEST-VALIDATOR', `Ciclo: ${result.total_tips} tips | overall ${result.overall.verdict.code} | ${result.summary.edge_real} edge_real | ${result.summary.bleed} bleed`);

  // Marcos novos (n=30, n=100, n=300) — sempre alerta
  const newMilestones = (result.milestones || []).filter(m => !_backtestMilestonesSeen.has(`${m.sport}|${m.milestone}`));
  for (const m of newMilestones) _backtestMilestonesSeen.add(`${m.sport}|${m.milestone}`);

  // Alerta condicional: bleed/noise ou marcos atingidos. Cooldown 24h pra DMs regulares.
  const hasBleed = result.summary.bleed > 0;
  const cooldownExpired = Date.now() - _lastBacktestAlert > 24 * 60 * 60 * 1000;
  if (!newMilestones.length && !hasBleed && !cooldownExpired) return;

  _lastBacktestAlert = Date.now();
  const tokenForAlert = resolveAlertsToken();
  if (!tokenForAlert) return;

  const overall = result.overall;
  const lines = [];
  lines.push(`*Overall (${result.total_tips} tips, ${result.days}d):* ${overall.verdict.label}`);
  lines.push(`  ROI ${overall.roi >= 0 ? '+' : ''}${overall.roi}% | Brier ${overall.brier ?? '-'} vs baseline ${overall.baseline_brier ?? '-'} (edge ${overall.brier_edge != null ? (overall.brier_edge >= 0 ? '+' : '') + overall.brier_edge : '-'})`);
  lines.push(`  Gates net: R$${overall.gates_net_reais >= 0 ? '+' : ''}${overall.gates_net_reais} (${overall.gates_blocked} bloqueadas)`);
  lines.push('');
  lines.push('*Por sport:*');
  for (const s of result.sports) {
    if (s.verdict.code === 'insufficient') continue;
    lines.push(`  ${s.verdict.label} *${s.sport}* (n=${s.n}) — ${s.verdict.detail}`);
  }
  if (newMilestones.length) {
    lines.push('');
    lines.push('*Marcos atingidos:*');
    for (const m of newMilestones) lines.push(`  🎯 ${m.sport}: ${m.milestone}`);
  }
  const msg = `🔬 *BACKTEST VALIDATOR*\n\n${lines.join('\n')}\n\n_Cron 1x/dia. Cooldown DM 24h._`;
  for (const adminId of ADMIN_IDS) await sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
}

// ── Post-Fix Monitor (cron diário) ──
// Roda /agents/post-fix-monitor com cutoff 2026-04-17 (gate-fix day) e alerta admin se houver alertas.
let _lastPostFixAlert = 0;
const _postFixAlertsSeen = new Set(); // `${sport}|${verdict_code}` — pra alertar só mudanças de estado

async function runPostFixMonitorCycle() {
  if (_isCycleMuted('postfix-monitor')) { return; }
  if (!ADMIN_IDS.size) return;
  const cutoff = process.env.POST_FIX_CUTOFF || '2026-04-17';
  let result = null;
  try {
    result = await serverGet(`/agents/post-fix-monitor?since=${cutoff}`).catch(() => null);
  } catch (e) {
    log('WARN', 'POST-FIX-MONITOR', `falhou: ${e.message}`);
    return;
  }
  if (!result?.ok) return;
  log('INFO', 'POST-FIX-MONITOR', `Ciclo: ${result.sports?.length || 0} sports | ${result.alerts?.length || 0} alertas`);

  const alerts = result.alerts || [];
  // Novos alertas: que não apareceram antes (estado muda de ok→alert)
  const newAlerts = alerts.filter(a => !_postFixAlertsSeen.has(`${a.sport}|${a.severity}`));
  for (const a of newAlerts) _postFixAlertsSeen.add(`${a.sport}|${a.severity}`);

  // Cooldown 24h pra DM regular mesmo sem alertas novos
  const cooldownExpired = Date.now() - _lastPostFixAlert > 24 * 60 * 60 * 1000;
  const hasHighSeverity = alerts.some(a => a.severity === 'high');
  if (!newAlerts.length && !hasHighSeverity && !cooldownExpired) return;

  _lastPostFixAlert = Date.now();
  const tokenForAlert = resolveAlertsToken();
  if (!tokenForAlert) return;

  const lines = [];
  lines.push(`*Cutoff:* ${result.cutoff} (${result.days_since_cutoff}d de dados pós-fix)`);
  lines.push('');
  if (alerts.length) {
    lines.push(`*${alerts.length} alerta(s):*`);
    for (const a of alerts) {
      const sev = a.severity === 'high' ? '🔴' : a.severity === 'medium' ? '🟡' : '⚪';
      lines.push(`  ${sev} ${a.sport}: ${a.message}`);
    }
  } else {
    lines.push('✅ *Nenhum alerta* — todos os sports dentro do esperado.');
  }
  lines.push('');
  lines.push('*Resumo por sport:*');
  for (const s of (result.sports || [])) {
    if (s.settled < 5) continue;
    const roiStr = s.roi != null ? (s.roi >= 0 ? '+' : '') + s.roi.toFixed(1) + '%' : 'n/a';
    lines.push(`  ${s.verdict.label.split(' — ')[0]} *${s.sport}* — n=${s.settled} ROI ${roiStr}`);
  }
  const msg = `🩺 *POST-FIX MONITOR*\n\n${lines.join('\n')}\n\n_Cron 1x/dia. Alerta se bleed ou flood+bleed em sport com n≥10._`;
  for (const adminId of ADMIN_IDS) await sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
}

// ── Model Calibration Watcher (semanal) ──
let _lastModelCalibAlert = 0;

// ── Path auto-guard: desativa em runtime hybrid/override path com CLV persistente negativo ──
// Map sport → { hybridDisabled: bool, overrideDisabled: bool, reasonHybrid, reasonOverride, since }
const _pathDisableRuntime = new Map();

function isPathDisabled(sport, path) {
  const e = _pathDisableRuntime.get(String(sport).toLowerCase());
  if (!e) return false;
  if (path === 'hybrid') return !!e.hybridDisabled;
  if (path === 'override') return !!e.overrideDisabled;
  return false;
}

async function runPathGuardCycle() {
  // Desativa via env PATH_GUARD_AUTO=false. Min sample 20 em 14d. Cutoff CLV ≤ -1%.
  if (/^(0|false|no)$/i.test(String(process.env.PATH_GUARD_AUTO || ''))) return;
  const minN = parseInt(process.env.PATH_GUARD_MIN_N || '20', 10);
  const cutoff = parseFloat(process.env.PATH_GUARD_CLV_CUTOFF || '-1.0');
  const daysWin = parseInt(process.env.PATH_GUARD_DAYS || '14', 10);
  try {
    const rows = db.prepare(`
      SELECT sport,
        CASE
          WHEN model_label LIKE '%+hybrid%' THEN 'hybrid'
          WHEN model_label LIKE '%+override%' THEN 'override'
          ELSE 'base'
        END AS path,
        COUNT(*) AS n,
        AVG(CASE WHEN clv_odds > 1 AND odds > 1 THEN (odds/clv_odds - 1) * 100 END) AS avg_clv,
        SUM(COALESCE(stake_reais, 0)) AS staked,
        SUM(COALESCE(profit_reais, 0)) AS profit
      FROM tips
      WHERE sent_at >= datetime('now', '-${daysWin} days')
        AND (archived IS NULL OR archived = 0)
        AND COALESCE(is_shadow, 0) = 0
        AND model_label IS NOT NULL
        AND result IN ('win','loss')
      GROUP BY sport, path
    `).all();

    const tokenForAlert = resolveAlertsToken();
    const alerts = [];
    const restored = [];
    const evaluated = new Set();
    for (const r of rows) {
      if (r.path === 'base') continue;
      evaluated.add(`${r.sport}|${r.path}`);
      const key = String(r.sport).toLowerCase();
      const curr = _pathDisableRuntime.get(key) || {};
      const field = r.path === 'hybrid' ? 'hybridDisabled' : 'overrideDisabled';
      const reasonField = r.path === 'hybrid' ? 'reasonHybrid' : 'reasonOverride';
      if (r.n >= minN && r.avg_clv != null && r.avg_clv <= cutoff) {
        if (!curr[field]) {
          curr[field] = true;
          curr[reasonField] = `CLV ${r.avg_clv.toFixed(2)}% n=${r.n} (${daysWin}d)`;
          curr.since = Date.now();
          _pathDisableRuntime.set(key, curr);
          alerts.push(`🚫 ${r.sport}/${r.path} desativado: CLV ${r.avg_clv.toFixed(2)}% em ${r.n} tips`);
          log('WARN', 'PATH-GUARD', `${r.sport}/${r.path} auto-disabled: CLV=${r.avg_clv.toFixed(2)}% n=${r.n}`);
        }
      } else if (curr[field] && r.n >= minN && r.avg_clv != null && r.avg_clv >= 0) {
        curr[field] = false;
        delete curr[reasonField];
        _pathDisableRuntime.set(key, curr);
        restored.push(`✅ ${r.sport}/${r.path} reativado: CLV ${r.avg_clv.toFixed(2)}%`);
        log('INFO', 'PATH-GUARD', `${r.sport}/${r.path} reativado: CLV=${r.avg_clv.toFixed(2)}%`);
      }
    }
    if ((alerts.length || restored.length) && tokenForAlert && ADMIN_IDS.size) {
      const msg = `🛡️ *PATH GUARD — ${daysWin}d*\n\n${[...alerts, ...restored].join('\n')}\n\n_Cutoff: CLV ≤ ${cutoff}% n≥${minN}. Reativa em CLV ≥ 0% n≥${minN}._`;
      if (!_isCycleMuted('path-guard')) for (const adminId of ADMIN_IDS) sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
    log('INFO', 'PATH-GUARD', `Ciclo OK — ${evaluated.size} buckets | ${alerts.length} disabled | ${restored.length} restored`);
  } catch (e) {
    log('WARN', 'PATH-GUARD', `falhou: ${e.message}`);
  }
}

// Auto-blocklist por liga. Avalia tips settled agrupadas por (sport, event_name);
// auto-bloqueia se n≥minN + ROI≤-25% + CLV≤-2% (dupla confirmação — evita ruído em amostra pequena).
// Restaura se blocked entry tem n≥minN recente + ROI ≥ -5%.
// Desativa via LEAGUE_GUARD_AUTO=false. Cooldown 7d pós /unblock-league manual.
async function runLeagueGuardCycle() {
  if (/^(0|false|no)$/i.test(String(process.env.LEAGUE_GUARD_AUTO || ''))) return;
  const minN = parseInt(process.env.LEAGUE_GUARD_MIN_N || '20', 10);
  const roiCutoff = parseFloat(process.env.LEAGUE_GUARD_ROI_CUTOFF || '-25');
  const clvCutoff = parseFloat(process.env.LEAGUE_GUARD_CLV_CUTOFF || '-2');
  const roiRestore = parseFloat(process.env.LEAGUE_GUARD_ROI_RESTORE || '-5');
  const daysWin = parseInt(process.env.LEAGUE_GUARD_DAYS || '30', 10);
  const cooldownMs = parseInt(process.env.LEAGUE_GUARD_COOLDOWN_DAYS || '7', 10) * 24 * 60 * 60 * 1000;
  try {
    const rows = db.prepare(`
      SELECT sport, event_name,
             COUNT(*) AS n,
             SUM(COALESCE(stake_reais, 0)) AS staked,
             SUM(COALESCE(profit_reais, 0)) AS profit,
             AVG(CASE WHEN clv_odds > 1 AND odds > 1 THEN (odds - clv_odds) / clv_odds * 100 END) AS avg_clv
      FROM tips
      WHERE sent_at >= datetime('now', '-${daysWin} days')
        AND (archived IS NULL OR archived = 0)
        AND COALESCE(is_shadow, 0) = 0
        AND result IN ('win','loss')
        AND event_name IS NOT NULL AND TRIM(event_name) != ''
      GROUP BY sport, event_name
      HAVING n >= ${minN}
    `).all();

    const tokenForAlert = resolveAlertsToken();
    const alerts = [];
    const restored = [];
    const now = Date.now();

    for (const r of rows) {
      const sport = String(r.sport || '').toLowerCase();
      const league = String(r.event_name || '').toLowerCase().trim();
      if (!sport || !league) continue;
      const entry = `${sport}:${league}`;
      const roi = r.staked > 0 ? (Number(r.profit) / Number(r.staked) * 100) : null;
      const clv = r.avg_clv != null ? Number(r.avg_clv) : null;
      const already = _leagueBlocklist.has(entry);
      const autoMeta = _autoBlockedLeagues.get(entry);

      // Auto-block: ROI ≤ roiCutoff AND (CLV ≤ clvCutoff OR CLV null). Cooldown pós unblock manual.
      if (!already && roi != null && roi <= roiCutoff && (clv == null || clv <= clvCutoff)) {
        const cooldownUntil = _leagueUnblockCooldown.get(entry) || 0;
        if (now < cooldownUntil) continue;
        _leagueBlocklist.add(entry);
        const reason = `ROI ${roi.toFixed(1)}% n=${r.n}${clv != null ? ` CLV ${clv.toFixed(1)}%` : ''}`;
        const meta = { reason, since: now, roi, clv, n: r.n };
        _autoBlockedLeagues.set(entry, meta);
        _persistBlocklistEntry(entry, 'auto', meta);
        alerts.push(`🚫 ${entry} — ${reason}`);
        log('WARN', 'LEAGUE-GUARD', `auto-blocked ${entry}: ${reason}`);
      }
      // Auto-restore: só de entries auto-managed (não mexe em manual/env)
      else if (autoMeta && roi != null && roi >= roiRestore && r.n >= minN) {
        _leagueBlocklist.delete(entry);
        _autoBlockedLeagues.delete(entry);
        _deleteBlocklistEntry(entry); // sem cooldown — recuperou legit
        restored.push(`✅ ${entry} — ROI recuperou pra ${roi.toFixed(1)}% (n=${r.n})`);
        log('INFO', 'LEAGUE-GUARD', `auto-restored ${entry}: ROI=${roi.toFixed(1)}%`);
      }
    }
    // 2026-04-28: TTL absoluto pra liga blocked sem novas tips. Antes deadlock
    // silencioso: ROI ruim → block → bloqueia novas tips → não acumula sample
    // → restore nunca dispara (n<minN sempre). Após LEAGUE_GUARD_AUTO_TTL_DAYS
    // (default 30d), força re-avaliação independente de N (limpa flag).
    const ttlDays = parseInt(process.env.LEAGUE_GUARD_AUTO_TTL_DAYS || '30', 10);
    if (ttlDays > 0) {
      const ttlMs = ttlDays * 86400 * 1000;
      for (const [entry, meta] of _autoBlockedLeagues) {
        if (meta.since && (now - meta.since) > ttlMs) {
          _leagueBlocklist.delete(entry);
          _autoBlockedLeagues.delete(entry);
          _deleteBlocklistEntry(entry);
          restored.push(`⏰ ${entry} — TTL ${ttlDays}d expirado, liberado pra re-avaliação`);
          log('INFO', 'LEAGUE-GUARD', `auto-restored ${entry} via TTL (${ttlDays}d)`);
        }
      }
    }

    if ((alerts.length || restored.length) && tokenForAlert && ADMIN_IDS.size) {
      const msg = `🛡️ *LEAGUE GUARD — ${daysWin}d*\n\n${[...alerts, ...restored].join('\n')}\n\n_Cutoff: ROI ≤ ${roiCutoff}% + CLV ≤ ${clvCutoff}% com n≥${minN}. Restaura em ROI ≥ ${roiRestore}%._\n_Use /blocked-leagues pra ver estado._`;
      if (!_isCycleMuted('league-guard')) for (const adminId of ADMIN_IDS) sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
    log('INFO', 'LEAGUE-GUARD', `Ciclo OK — ${rows.length} ligas avaliadas | ${alerts.length} blocked | ${restored.length} restored`);
  } catch (e) {
    log('WARN', 'LEAGUE-GUARD', `falhou: ${e.message}`);
  }
}

// Auto-guard por bucket de odds. Mesma filosofia do league-guard mas agrupa por
// (sport, bucket fixo). Buckets: 1.40-1.70, 1.70-2.20, 2.20-3.00, 3.00-99.
// Auto-block: n≥minN AND ROI≤cutoff AND CLV≤clvCutoff.
// Auto-restore: ROI ≥ restore com nova amostra.
// Desativa via ODDS_BUCKET_GUARD_AUTO=false.
const _ODDS_BUCKET_DEFS = [
  { min: 1.40, max: 1.70 },
  { min: 1.70, max: 2.20 },
  { min: 2.20, max: 3.00 },
  { min: 3.00, max: 99.00 },
];
function _bucketOfOdd(odd) {
  for (const b of _ODDS_BUCKET_DEFS) {
    if (odd >= b.min && odd < b.max) return b;
  }
  return null;
}
async function runOddsBucketGuardCycle() {
  if (/^(0|false|no)$/i.test(String(process.env.ODDS_BUCKET_GUARD_AUTO || ''))) return;
  const minN = parseInt(process.env.ODDS_BUCKET_GUARD_MIN_N || '30', 10);
  const roiCutoff = parseFloat(process.env.ODDS_BUCKET_GUARD_ROI_CUTOFF || '-10');
  const clvCutoff = parseFloat(process.env.ODDS_BUCKET_GUARD_CLV_CUTOFF || '-2');
  const roiRestore = parseFloat(process.env.ODDS_BUCKET_GUARD_ROI_RESTORE || '-2');
  const daysWin = parseInt(process.env.ODDS_BUCKET_GUARD_DAYS || '30', 10);
  try {
    const obg = require('./lib/odds-bucket-gate');
    const rows = db.prepare(`
      SELECT sport, odds, clv_odds, result, profit_reais, COALESCE(stake_reais, 0) AS stake
      FROM tips
      WHERE sent_at >= datetime('now', '-${daysWin} days')
        AND (archived IS NULL OR archived = 0)
        AND COALESCE(is_shadow, 0) = 0
        AND result IN ('win','loss')
        AND odds IS NOT NULL AND odds > 1
    `).all();

    // Agrega por (sport, bucket)
    const agg = new Map(); // key "sport|min|max" → { n, wins, staked, profit, clvSum, clvN, sport, b }
    for (const r of rows) {
      const odd = Number(r.odds);
      const b = _bucketOfOdd(odd);
      if (!b) continue;
      const sport = obg.normSport(r.sport).toLowerCase();
      const key = `${sport}|${b.min}|${b.max}`;
      let a = agg.get(key);
      if (!a) {
        a = { sport, b, n: 0, wins: 0, staked: 0, profit: 0, clvSum: 0, clvN: 0 };
        agg.set(key, a);
      }
      a.n++;
      if (r.result === 'win') a.wins++;
      a.staked += Number(r.stake) || 0;
      a.profit += Number(r.profit_reais) || 0;
      if (Number.isFinite(r.clv_odds) && r.clv_odds > 1) {
        a.clvSum += ((odd - r.clv_odds) / r.clv_odds) * 100;
        a.clvN++;
      }
    }

    const tokenForAlert = resolveAlertsToken();
    const alerts = [];
    const restored = [];
    const autoBlocked = obg.getAutoBlocks();

    for (const a of agg.values()) {
      if (a.n < minN) continue;
      const roi = a.staked > 0 ? (a.profit / a.staked * 100) : null;
      const clv = a.clvN > 0 ? (a.clvSum / a.clvN) : null;
      const entry = `${a.sport}:${a.b.min.toFixed(2)}-${a.b.max.toFixed(2)}`;

      const already = obg.getDbBlocklist().has(entry);
      const wasAuto = autoBlocked.has(entry);

      // Auto-block
      if (!already && roi != null && roi <= roiCutoff && (clv == null || clv <= clvCutoff)) {
        const reason = `ROI ${roi.toFixed(1)}% n=${a.n}${clv != null ? ` CLV ${clv.toFixed(1)}%` : ''}`;
        const meta = { reason, since: Date.now(), roi, clv, n: a.n };
        const added = obg.autoBlock(db, a.sport, a.b.min, a.b.max, meta);
        if (added) {
          alerts.push(`🚫 ${entry} — ${reason}`);
          log('WARN', 'BUCKET-GUARD', `auto-blocked ${entry}: ${reason}`);
        }
      }
      // Auto-restore (só auto entries)
      else if (wasAuto && roi != null && roi >= roiRestore && a.n >= minN) {
        if (obg.autoRestore(db, entry)) {
          restored.push(`✅ ${entry} — ROI ${roi.toFixed(1)}% (n=${a.n})`);
          log('INFO', 'BUCKET-GUARD', `auto-restored ${entry}: ROI=${roi.toFixed(1)}%`);
        }
      }
    }

    if ((alerts.length || restored.length) && tokenForAlert && ADMIN_IDS.size) {
      const msg = `🛡️ *BUCKET GUARD — ${daysWin}d*\n\n${[...alerts, ...restored].join('\n')}\n\n_Cutoff: ROI ≤ ${roiCutoff}% + CLV ≤ ${clvCutoff}% com n≥${minN}. Restaura em ROI ≥ ${roiRestore}%._`;
      if (!_isCycleMuted('odds-bucket-guard')) for (const adminId of ADMIN_IDS) sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
    log('INFO', 'BUCKET-GUARD', `Ciclo OK — ${agg.size} (sport,bucket) avaliados | ${alerts.length} blocked | ${restored.length} restored`);
  } catch (e) {
    log('WARN', 'BUCKET-GUARD', `falhou: ${e.message}`);
  }
}

// Resolve min/max odd pra MT scanner. Precedência: env per-sport explícito >
// gates_runtime_state (auto-guard) > default. Retorna { minOdd, maxOdd } ou
// undefined em cada lado quando não há gate.
//
// Env keys: {SPORT_PREFIX}_MARKET_SCAN_MIN_ODD / _MAX_ODD
//   lol → LOL_MARKET_SCAN_*
//   dota2 → DOTA_MARKET_SCAN_*
//   cs2 → CS_MARKET_SCAN_*
//   tennis → TENNIS_MARKET_SCAN_*
// Aplica esports-correlation em tips MT do scanner (LoL/CS2/Dota2/Val).
// Propaga `correlationDiscount` em cada tip — promote path multiplica stake por (1-discount).
// Loga top correlações detectadas (|c|>0.3).
function _applyEsportsCorrelation(found, sport, match) {
  const { adjustStakesForCorrelation, computeMarketCorrelation } = require('./lib/esports-correlation');
  const tipsWithKelly = found.map(t => ({
    ...t,
    kellyStake: +((t.pModel - (1 - t.pModel) / (t.odd - 1)) * 100).toFixed(2) || 0,
  }));
  const adjusted = adjustStakesForCorrelation(tipsWithKelly);
  const pairs = [];
  for (let i = 0; i < found.length; i++) {
    for (let j = i + 1; j < found.length; j++) {
      const c = computeMarketCorrelation(found[i], found[j]);
      if (Math.abs(c) > 0.3) pairs.push(`${found[i].label}↔${found[j].label}=${c.toFixed(2)}`);
    }
  }
  if (pairs.length) {
    log('INFO', `${String(sport).toUpperCase()}-CORR`, `${match.team1} vs ${match.team2}: ${pairs.slice(0, 3).join(' | ')}`);
  }
  return found.map((t, i) => ({ ...t, correlationDiscount: adjusted[i].correlationDiscount }));
}

function _resolveMtOddBounds(sport, opts = {}) {
  const envPrefix = sport === 'dota2' ? 'DOTA' : sport === 'cs2' ? 'CS' : String(sport).toUpperCase();
  const envMin = parseFloat(process.env[`${envPrefix}_MARKET_SCAN_MIN_ODD`]);
  const envMax = parseFloat(process.env[`${envPrefix}_MARKET_SCAN_MAX_ODD`]);
  let minOdd = Number.isFinite(envMin) && envMin > 1 ? envMin : null;
  let maxOdd = Number.isFinite(envMax) && envMax > 1 ? envMax : null;
  // Env=0 desativa explicitamente o gate (impede DB override). Detectado via NaN
  // não match, então check string "0".
  const envMinStr = process.env[`${envPrefix}_MARKET_SCAN_MIN_ODD`];
  const envMaxStr = process.env[`${envPrefix}_MARKET_SCAN_MAX_ODD`];
  const minDisabled = envMinStr === '0' || envMinStr === '0.0';
  const maxDisabled = envMaxStr === '0' || envMaxStr === '0.0';
  // Consulta DB auto-guard se env não setado (e não desativado).
  if (minOdd == null && !minDisabled) {
    try {
      const grs = require('./lib/gates-runtime-state');
      const dbVal = grs.getGateValue(sport, grs.GATE_KEYS.MT_SCAN_MIN_ODD);
      if (dbVal != null && dbVal > 1) minOdd = dbVal;
    } catch (_) {}
  }
  if (maxOdd == null && !maxDisabled) {
    try {
      const grs = require('./lib/gates-runtime-state');
      const dbVal = grs.getGateValue(sport, grs.GATE_KEYS.MT_SCAN_MAX_ODD);
      if (dbVal != null && dbVal > 1) maxOdd = dbVal;
    } catch (_) {}
  }
  // Fallback default per opts (caller pode forçar default mesmo sem dados auto).
  if (minOdd == null && Number.isFinite(opts.defaultMinOdd) && opts.defaultMinOdd > 1 && !minDisabled) {
    minOdd = opts.defaultMinOdd;
  }
  if (maxOdd == null && Number.isFinite(opts.defaultMaxOdd) && opts.defaultMaxOdd > 1 && !maxDisabled) {
    maxOdd = opts.defaultMaxOdd;
  }
  return {
    minOdd: minOdd != null ? minOdd : undefined,
    maxOdd: maxOdd != null ? maxOdd : undefined,
  };
}

// MT shadow per-bucket guard. Análogo ao runOddsBucketGuardCycle mas opera em
// market_tips_shadow. Detecta leak por (sport, bucket de odd) e seta
// MT_SCAN_MIN_ODD / MT_SCAN_MAX_ODD per-sport via gates_runtime_state. Scanner
// callers leem o valor (env > DB auto > default) ao construir scan.
//
// Lógica: pra cada sport com n total ≥ MIN_TOTAL, scan buckets sorted por lower
// bound. Identifica região contígua "saudável" (ROI > -10% OU n insuficiente).
// min_odd = lower bound da região saudável; max_odd = upper bound.
// Se ÚNICO bucket sangra mas isolado (não é extremo do range), não setamos —
// um floor/cap só é útil se o leak é nas bordas.
//
// Toggle MT_BUCKET_GUARD_AUTO=false desativa.
const _MT_BUCKET_DEFS = [
  { min: 1.00, max: 1.30 },
  { min: 1.30, max: 1.50 },
  { min: 1.50, max: 1.80 },
  { min: 1.80, max: 2.20 },
  { min: 2.20, max: 3.00 },
  { min: 3.00, max: 99.0 },
];
function _mtBucketOfOdd(odd) {
  for (const b of _MT_BUCKET_DEFS) {
    if (odd >= b.min && odd < b.max) return b;
  }
  return null;
}
async function runMtBucketGuardCycle() {
  if (/^(0|false|no)$/i.test(String(process.env.MT_BUCKET_GUARD_AUTO || ''))) return;
  const minN = parseInt(process.env.MT_BUCKET_GUARD_MIN_N || '20', 10);
  const minTotal = parseInt(process.env.MT_BUCKET_GUARD_MIN_TOTAL || '60', 10);
  const roiCutoff = parseFloat(process.env.MT_BUCKET_GUARD_ROI_CUTOFF || '-10');
  const clvCutoff = parseFloat(process.env.MT_BUCKET_GUARD_CLV_CUTOFF || '-2');
  const daysWin = parseInt(process.env.MT_BUCKET_GUARD_DAYS || '30', 10);
  try {
    const grs = require('./lib/gates-runtime-state');
    // Verifica se a coluna existe (ambiente legado pode não ter rodado migration 054)
    let hasShadow = false;
    try {
      const t = db.prepare("SELECT 1 FROM sqlite_master WHERE type='table' AND name='market_tips_shadow'").get();
      hasShadow = !!t;
    } catch (_) {}
    if (!hasShadow) return;

    const rows = db.prepare(`
      SELECT sport, odd, p_model, result, COALESCE(stake_units, 1) AS stake,
             profit_units, clv_pct
      FROM market_tips_shadow
      WHERE created_at >= datetime('now', '-${daysWin} days')
        AND result IN ('win','loss')
        AND odd IS NOT NULL AND odd > 1
    `).all();

    // Aggregate by (sport, bucket)
    const agg = new Map(); // key sport|min|max → bucket stats
    const sportTotals = new Map(); // sport → total settled n (pra MIN_TOTAL gate)
    for (const r of rows) {
      const odd = Number(r.odd);
      const b = _mtBucketOfOdd(odd);
      if (!b) continue;
      const sport = String(r.sport || '').toLowerCase().trim();
      if (!sport) continue;
      const key = `${sport}|${b.min}|${b.max}`;
      let a = agg.get(key);
      if (!a) {
        a = { sport, b, n: 0, wins: 0, staked: 0, profit: 0, clvSum: 0, clvN: 0 };
        agg.set(key, a);
      }
      a.n++;
      if (r.result === 'win') a.wins++;
      a.staked += Number(r.stake) || 0;
      a.profit += Number(r.profit_units) || 0;
      if (Number.isFinite(r.clv_pct)) {
        a.clvSum += r.clv_pct;
        a.clvN++;
      }
      sportTotals.set(sport, (sportTotals.get(sport) || 0) + 1);
    }

    // Pra cada sport com sample suficiente, decide min/max odd.
    const tokenForAlert = resolveAlertsToken();
    const changes = [];
    for (const [sport, total] of sportTotals) {
      if (total < minTotal) continue;

      // Junta buckets do sport, sort por lower bound.
      const sportBuckets = _MT_BUCKET_DEFS.map(def => {
        const a = agg.get(`${sport}|${def.min}|${def.max}`);
        const roi = a && a.staked > 0 ? (a.profit / a.staked * 100) : null;
        const clv = a && a.clvN > 0 ? (a.clvSum / a.clvN) : null;
        return { def, n: a?.n || 0, roi, clv };
      });

      // Bucket é "leak" se: n ≥ minN E (ROI ≤ cutoff E (CLV null OU CLV ≤ clvCutoff)).
      // n insuficiente = inconclusive (nem saudável nem leak).
      const isLeak = (bk) => bk.n >= minN
        && bk.roi != null && bk.roi <= roiCutoff
        && (bk.clv == null || bk.clv <= clvCutoff);
      const isHealthy = (bk) => bk.n >= minN
        && bk.roi != null && bk.roi > roiCutoff;

      // Detecta leak nas BORDAS — só seta gate se leak é em bucket extremo
      // (primeiro low ou último high). Leak no meio sem cobertura nas bordas
      // não faz sentido cortar via min/max.
      // Find lowest non-leak bucket → min_odd suggestion = its lower bound
      let suggestMin = null;
      for (let i = 0; i < sportBuckets.length; i++) {
        const bk = sportBuckets[i];
        if (isLeak(bk)) continue; // pula leak — quero o primeiro saudável/inconclusivo
        suggestMin = bk.def.min;
        break;
      }
      // Find highest non-leak bucket → max_odd suggestion = its upper bound
      let suggestMax = null;
      for (let i = sportBuckets.length - 1; i >= 0; i--) {
        const bk = sportBuckets[i];
        if (isLeak(bk)) continue;
        suggestMax = bk.def.max >= 99 ? null : bk.def.max; // 99 = sem cap
        break;
      }
      // Só aplica MIN_ODD se o bucket abaixo realmente sangra com sample.
      const lowBucket = sportBuckets[0];
      const wantsMin = suggestMin && suggestMin > 1.0 && lowBucket.n >= minN
        && lowBucket.roi != null && lowBucket.roi <= roiCutoff;
      // MAX_ODD só se bucket acima da fronteira sangra com sample.
      const highBucket = sportBuckets[sportBuckets.length - 1];
      const wantsMax = suggestMax && highBucket.n >= minN
        && highBucket.roi != null && highBucket.roi <= roiCutoff;

      // Aplica via gates-runtime-state. Não sobrescreve manual.
      const evidence = sportBuckets.map(bk => ({
        bucket: `${bk.def.min}-${bk.def.max}`,
        n: bk.n,
        roi: bk.roi != null ? +bk.roi.toFixed(1) : null,
        clv: bk.clv != null ? +bk.clv.toFixed(2) : null,
      }));

      const applyMt = (gateKey, newVal, label) => {
        if (newVal == null) {
          // Remove auto se não há mais leak.
          const meta = grs.getGateMeta(sport, gateKey);
          if (meta && meta.source === 'auto') {
            grs.removeAuto(db, sport, gateKey);
            changes.push(`✅ ${sport} ${label} — restaurado (leak desapareceu)`);
            log('INFO', 'MT-BUCKET-GUARD', `${sport}/${gateKey}: removido (no leak)`);
          }
          return;
        }
        const cur = grs.getGateValue(sport, gateKey);
        const meta = grs.getGateMeta(sport, gateKey);
        if (meta && meta.source === 'manual') return; // respeita manual
        if (cur != null && Math.abs(cur - newVal) < 0.001) return; // no change
        grs.setAuto(db, sport, gateKey, newVal, {
          reason: `auto from MT shadow ${daysWin}d`,
          evidence,
        });
        changes.push(`🛡️ ${sport} ${label}=${newVal.toFixed(2)} (was ${cur != null ? cur.toFixed(2) : 'unset'})`);
        log('INFO', 'MT-BUCKET-GUARD', `${sport}/${gateKey}: ${cur ?? 'unset'} → ${newVal}`);
      };

      applyMt(grs.GATE_KEYS.MT_SCAN_MIN_ODD, wantsMin ? suggestMin : null, 'MIN_ODD');
      applyMt(grs.GATE_KEYS.MT_SCAN_MAX_ODD, wantsMax ? suggestMax : null, 'MAX_ODD');
    }

    if (changes.length && tokenForAlert && ADMIN_IDS.size) {
      const msg = `🛡️ *MT BUCKET GUARD — ${daysWin}d*\n\n${changes.join('\n')}\n\n_Cutoff: ROI ≤ ${roiCutoff}% + CLV ≤ ${clvCutoff}% com n≥${minN}/bucket. Sport precisa ≥${minTotal} settled total._`;
      for (const adminId of ADMIN_IDS) sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
    log('INFO', 'MT-BUCKET-GUARD', `Ciclo OK — sports=${sportTotals.size} | mudanças=${changes.length}`);
  } catch (e) {
    log('WARN', 'MT-BUCKET-GUARD', `falhou: ${e.message}`);
  }
}

// Auto-tune dos gates pre-match EV bonus + max stake cap. Mesma filosofia
// dos outros guards (league, bucket): cron 12h, persiste DB, DM admin em
// changes. Toggle ODDS_GATES_AUTOTUNE=false desativa.
async function runGatesAutoTuneCycle() {
  if (/^(0|false|no)$/i.test(String(process.env.GATES_AUTOTUNE_AUTO || ''))) return;
  const minN = parseInt(process.env.GATES_AUTOTUNE_MIN_N || '20', 10);
  const daysWin = parseInt(process.env.GATES_AUTOTUNE_DAYS || '30', 10);
  const liveGapTriggerPp = parseFloat(process.env.GATES_AUTOTUNE_PRE_GAP_PP || '20');
  const liveGapReleasePp = parseFloat(process.env.GATES_AUTOTUNE_PRE_RELEASE_PP || '5');
  const stakeRoiCutoff = parseFloat(process.env.GATES_AUTOTUNE_STAKE_ROI_CUTOFF || '-25');
  const maxBonus = parseFloat(process.env.GATES_AUTOTUNE_MAX_BONUS || '8');
  try {
    const grs = require('./lib/gates-runtime-state');
    const rows = db.prepare(`
      SELECT sport, is_live, odds, stake, result,
             COALESCE(stake_reais, 0) AS staked,
             COALESCE(profit_reais, 0) AS profit
      FROM tips
      WHERE sent_at >= datetime('now', '-${daysWin} days')
        AND (archived IS NULL OR archived = 0)
        AND COALESCE(is_shadow, 0) = 0
        AND result IN ('win','loss')
        AND odds IS NOT NULL AND odds > 1
    `).all();

    function parseStakeU(s) {
      const n = parseFloat(String(s || '').replace(/u/i, ''));
      return Number.isFinite(n) ? n : null;
    }
    function bucketStake(u) {
      if (u == null) return null;
      if (u < 1.5) return 1;
      if (u < 2.5) return 2;
      if (u < 3.5) return 3;
      return 4;
    }

    // Aggregate per (sport, isLive) e (sport, stakeBucket)
    const sports = new Set();
    const byLive = new Map();   // `${sport}|${0|1}` → {n,wins,staked,profit}
    const byStake = new Map();  // `${sport}|${bucket}` → {n,wins,staked,profit}
    for (const r of rows) {
      const sp = String(r.sport || '').toLowerCase();
      sports.add(sp);
      const liveK = `${sp}|${r.is_live ? 1 : 0}`;
      let lv = byLive.get(liveK);
      if (!lv) { lv = { n: 0, wins: 0, staked: 0, profit: 0 }; byLive.set(liveK, lv); }
      lv.n++; if (r.result === 'win') lv.wins++;
      lv.staked += Number(r.staked) || 0; lv.profit += Number(r.profit) || 0;

      const su = parseStakeU(r.stake);
      const bk = bucketStake(su);
      if (bk != null) {
        const stK = `${sp}|${bk}`;
        let st = byStake.get(stK);
        if (!st) { st = { n: 0, wins: 0, staked: 0, profit: 0, bucket: bk }; byStake.set(stK, st); }
        st.n++; if (r.result === 'win') st.wins++;
        st.staked += Number(r.staked) || 0; st.profit += Number(r.profit) || 0;
      }
    }
    function roiOf(a) { return a.staked > 0 ? (a.profit / a.staked * 100) : null; }

    const tokenForAlert = resolveAlertsToken();
    const changes = [];

    for (const sp of sports) {
      // ── PRE-match EV bonus auto-tune ──
      // Não toca em sports onde env per-sport está manualmente setada
      const envKey = `${sp.toUpperCase()}_PRE_MATCH_EV_BONUS`;
      const envSet = process.env[envKey] != null && process.env[envKey] !== '';
      if (!envSet) {
        const pre = byLive.get(`${sp}|0`);
        const live = byLive.get(`${sp}|1`);
        if (pre && pre.n >= minN && live && live.n >= minN) {
          const preRoi = roiOf(pre);
          const liveRoi = roiOf(live);
          if (preRoi != null && liveRoi != null) {
            const gap = liveRoi - preRoi; // positivo = LIVE melhor que PRE
            const cur = grs.getGateValue(sp, grs.GATE_KEYS.PRE_MATCH_EV_BONUS) ?? 0;
            let target = cur;
            if (gap >= liveGapTriggerPp && cur < maxBonus) target = Math.min(maxBonus, cur + 1);
            else if (gap < liveGapReleasePp && cur > 0) target = Math.max(0, cur - 1);
            if (target !== cur) {
              const reason = `PRE ${preRoi.toFixed(1)}% vs LIVE ${liveRoi.toFixed(1)}% (gap ${gap.toFixed(1)}pp)`;
              const evidence = { preN: pre.n, liveN: live.n, preRoi: +preRoi.toFixed(2), liveRoi: +liveRoi.toFixed(2), gap: +gap.toFixed(2) };
              if (target > 0) {
                grs.setAuto(db, sp, grs.GATE_KEYS.PRE_MATCH_EV_BONUS, target, { reason, evidence });
                changes.push(`📈 ${sp} PRE_MATCH_EV_BONUS: ${cur}pp → ${target}pp (${reason})`);
              } else {
                grs.removeAuto(db, sp, grs.GATE_KEYS.PRE_MATCH_EV_BONUS);
                changes.push(`✅ ${sp} PRE_MATCH_EV_BONUS removido (${reason})`);
              }
              log('INFO', 'GATES-AUTOTUNE', `${sp} pre_match_ev_bonus: ${cur} → ${target} | ${reason}`);
            }
          }
        }
      }

      // ── Max stake cap auto-tune ──
      const capEnvKey = `${sp.toUpperCase()}_MAX_STAKE_UNITS`;
      const capEnvSet = process.env[capEnvKey] != null && process.env[capEnvKey] !== '';
      if (!capEnvSet) {
        const buckets = [1, 2, 3, 4]
          .map(b => byStake.get(`${sp}|${b}`))
          .filter(b => b && b.n >= 10);
        if (buckets.length >= 2) {
          // Find topmost bucket with healthy ROI (>= -10%); cap at that
          let healthyTop = null;
          for (const b of buckets) {
            const roi = roiOf(b);
            if (roi != null && roi >= -10) healthyTop = b.bucket;
          }
          // Find leak at higher bucket
          let leakBucket = null;
          for (const b of buckets) {
            const roi = roiOf(b);
            if (roi != null && roi <= stakeRoiCutoff && (healthyTop == null || b.bucket > healthyTop)) {
              leakBucket = b.bucket;
              break;
            }
          }
          const cur = grs.getGateValue(sp, grs.GATE_KEYS.MAX_STAKE_UNITS);
          let target = cur;
          if (leakBucket != null && healthyTop != null) {
            target = healthyTop; // cap no maior bucket saudável
          } else if (leakBucket == null && cur != null) {
            // Sem leak detectado — libera cap se foi auto
            const meta = grs.getGateMeta(sp, grs.GATE_KEYS.MAX_STAKE_UNITS);
            if (meta?.source === 'auto') target = null;
          }
          if (target !== cur) {
            if (target != null && target > 0) {
              const reason = `bucket ${leakBucket}u ROI ${roiOf(buckets.find(b => b.bucket === leakBucket))?.toFixed(1)}% < ${stakeRoiCutoff}%, healthy top=${healthyTop}u`;
              const evidence = { buckets: buckets.map(b => ({ bucket: b.bucket, n: b.n, roi: +(roiOf(b) || 0).toFixed(2) })) };
              grs.setAuto(db, sp, grs.GATE_KEYS.MAX_STAKE_UNITS, target, { reason, evidence });
              changes.push(`📉 ${sp} MAX_STAKE_UNITS: ${cur ?? '∞'}u → ${target}u (${reason})`);
              log('INFO', 'GATES-AUTOTUNE', `${sp} max_stake_units: ${cur ?? '∞'} → ${target}`);
            } else {
              grs.removeAuto(db, sp, grs.GATE_KEYS.MAX_STAKE_UNITS);
              changes.push(`✅ ${sp} MAX_STAKE_UNITS cap removido (todos buckets saudáveis)`);
              log('INFO', 'GATES-AUTOTUNE', `${sp} max_stake_units removido`);
            }
          }
        }
      }
    }

    if (changes.length && tokenForAlert && ADMIN_IDS.size) {
      const msg = `🛡️ *GATES AUTO-TUNE — ${daysWin}d*\n\n${changes.join('\n')}\n\n_Cron 12h. Env vars manuais sempre sobrepõem auto-tune._`;
      for (const adminId of ADMIN_IDS) sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
    log('INFO', 'GATES-AUTOTUNE', `Ciclo OK — ${sports.size} sports avaliados | ${changes.length} mudanças`);
  } catch (e) {
    log('WARN', 'GATES-AUTOTUNE', `falhou: ${e.message}`);
  }
}

// Reusable: gera relatório pipeline pra /pipeline-status cmd + digest cron.
// Retorna { txt, hasCritical }.
async function buildPipelineStatusReport(days = 30) {
  const ba = await serverGet('/bankroll-audit').catch(() => null);
  const totalInit = Number(ba?.total_initial || 0);
  const totalStored = Number(ba?.total_current_stored || 0);
  const deltaAbs = totalStored - totalInit;
  const deltaPct = totalInit > 0 ? (deltaAbs / totalInit * 100) : 0;

  const sports = ['lol', 'dota2', 'mma', 'tennis', 'cs', 'valorant', 'football', 'tabletennis', 'darts', 'snooker'];
  const sportRows = [];
  for (const sp of sports) {
    const extraSql = sp === 'dota2'
      ? " OR (sport = 'esports' AND (match_id LIKE 'dota2_%' OR LOWER(COALESCE(event_name,'')) LIKE '%dota%'))"
      : sp === 'lol'
        ? " OR (sport = 'esports' AND match_id NOT LIKE 'dota2_%' AND LOWER(COALESCE(event_name,'')) NOT LIKE '%dota%')"
        : "";
    const r = db.prepare(`
      SELECT COUNT(*) AS n,
             COALESCE(SUM(stake_reais), 0) AS staked,
             COALESCE(SUM(profit_reais), 0) AS profit
      FROM tips
      WHERE sent_at >= datetime('now', '-${days} days')
        AND (archived IS NULL OR archived = 0)
        AND COALESCE(is_shadow, 0) = 0
        AND result IN ('win','loss')
        AND (sport = ?${extraSql})
    `).get(sp);
    const n = Number(r?.n || 0);
    const staked = Number(r?.staked || 0);
    const profit = Number(r?.profit || 0);
    const roi = staked > 0 ? (profit / staked * 100) : null;
    if (n > 0) sportRows.push({ sport: sp, n, roi, profit });
  }
  sportRows.sort((a, b) => (a.roi ?? 0) - (b.roi ?? 0));

  const bandOf = (roi, n) => {
    if (n < 10 || roi == null) return '?';
    if (roi >= 5) return 'healthy';
    if (roi >= 0) return 'neutral';
    if (roi >= -10) return 'warn';
    if (roi >= -25) return 'review';
    return 'leak';
  };
  const bandIcon = { healthy: '🟢', neutral: '⚪', warn: '🟡', review: '🟠', leak: '🔴', '?': '⚫' };

  const leaksRows = db.prepare(`
    SELECT sport, event_name, COUNT(*) AS n,
           COALESCE(SUM(stake_reais), 0) AS staked,
           COALESCE(SUM(profit_reais), 0) AS profit
    FROM tips
    WHERE sent_at >= datetime('now', '-${days} days')
      AND (archived IS NULL OR archived = 0)
      AND COALESCE(is_shadow, 0) = 0
      AND result IN ('win','loss')
      AND event_name IS NOT NULL AND TRIM(event_name) != ''
    GROUP BY sport, event_name
    HAVING n >= 5
  `).all();
  const leaks = leaksRows
    .map(r => ({
      sport: r.sport,
      league: (r.event_name || '').slice(0, 30),
      n: r.n,
      roi: r.staked > 0 ? (r.profit / r.staked * 100) : null,
      profit: Number(r.profit || 0),
    }))
    .filter(r => r.profit < -5 && r.roi != null && r.roi < 0)
    .sort((a, b) => a.profit - b.profit)
    .slice(0, 3);

  const now = Date.now();
  const autoCount = _autoBlockedLeagues.size;
  const manualCount = _leagueBlocklist.size - autoCount;
  const activeCooldowns = [..._leagueUnblockCooldown.values()].filter(ts => ts > now).length;

  let txt = `🏥 *PIPELINE STATUS — ${days}d*\n\n`;
  const deltaIcon = deltaPct >= 0 ? '🟢' : deltaPct >= -10 ? '🟡' : '🔴';
  txt += `${deltaIcon} *Banca:* R$${totalStored.toFixed(2)} / R$${totalInit.toFixed(2)} `;
  txt += `(${deltaAbs >= 0 ? '+' : ''}R$${deltaAbs.toFixed(2)} · ${deltaPct >= 0 ? '+' : ''}${deltaPct.toFixed(1)}%)\n\n`;

  txt += `*Sports (ROI ${days}d):*\n`;
  if (!sportRows.length) {
    txt += `_Sem tips settled._\n`;
  } else {
    const problematicBands = new Set(['warn', 'review', 'leak']);
    const problematicOnly = sportRows.filter(s => problematicBands.has(bandOf(s.roi, s.n)));
    const toShow = problematicOnly.length ? problematicOnly : sportRows.slice(0, 5);
    for (const s of toShow) {
      const band = bandOf(s.roi, s.n);
      const roiStr = s.roi != null ? (s.roi >= 0 ? '+' : '') + s.roi.toFixed(1) + '%' : '—';
      txt += `${bandIcon[band]} ${s.sport.padEnd(9)} n=${String(s.n).padStart(3)} ROI ${roiStr.padStart(7)} P&L R$${s.profit.toFixed(2)} \`${band}\`\n`;
    }
    if (problematicOnly.length && problematicOnly.length < sportRows.length) {
      txt += `_+${sportRows.length - problematicOnly.length} sports healthy/neutral omitidos_\n`;
    }
  }

  txt += `\n*Blocklist:*\n`;
  txt += `🤖 ${autoCount} auto · 🔧 ${manualCount} manual/env · ⏸️ ${activeCooldowns} cooldowns\n`;

  if (leaks.length) {
    txt += `\n*Top leaks (liga):*\n`;
    for (const l of leaks) {
      const roiStr = l.roi != null ? l.roi.toFixed(1) + '%' : '—';
      txt += `🚨 ${l.sport}/${l.league} — n=${l.n} ROI ${roiStr} · R$${l.profit.toFixed(2)}\n`;
    }
  }

  const criticalBands = sportRows.filter(s => bandOf(s.roi, s.n) === 'leak');
  const reviewBands = sportRows.filter(s => bandOf(s.roi, s.n) === 'review');
  const hasCritical = !!(criticalBands.length || leaks.length || deltaPct <= -15);
  if (criticalBands.length || reviewBands.length || leaks.length) {
    txt += `\n*Ações sugeridas:*\n`;
    for (const s of criticalBands) txt += `• \`KELLY_${s.sport.toUpperCase()}_ALTA=0.10\` ou /pause-sport ${s.sport}\n`;
    for (const s of reviewBands) txt += `• \`KELLY_${s.sport.toUpperCase()}_ALTA=0.175\` (review band)\n`;
    if (leaks.length) txt += `• \`/block-league <sport> <substring>\` pras ligas acima\n`;
  } else {
    txt += `\n✅ _Pipeline saudável — nada crítico_\n`;
  }
  txt += `\n_Detalhes: /kelly · /clv-league · /blocked-leagues · /bankroll-audit_`;

  return { txt, hasCritical, metrics: { totalInit, totalStored, deltaPct, sportRows, leaks, autoCount, manualCount, activeCooldowns } };
}

// Adaptive DM digest: critical=24h cooldown (urgent), healthy=6d (weekly),
// transições critical→healthy envian "RECOVERED" fora de cooldown.
// Desativa via PIPELINE_DIGEST_AUTO=false. Só DM se houver >= 1 admin registrado.
let _lastPipelineDigestAt = 0;
let _lastPipelineDigestState = null; // null | 'critical' | 'healthy'
async function runPipelineDigestCycle() {
  if (/^(0|false|no)$/i.test(String(process.env.PIPELINE_DIGEST_AUTO || ''))) return;
  if (!ADMIN_IDS.size) return;
  try {
    const days = Math.max(7, Math.min(90, parseInt(process.env.PIPELINE_DIGEST_DAYS || '30', 10)));
    const { txt, hasCritical } = await buildPipelineStatusReport(days);
    const newState = hasCritical ? 'critical' : 'healthy';
    const wasRecovered = _lastPipelineDigestState === 'critical' && newState === 'healthy';
    const wasEscalated = _lastPipelineDigestState === 'healthy' && newState === 'critical';

    // Cooldown adaptativo: critical 24h, healthy 6d. Bypass em qualquer transição (escalation ou recovery).
    // Bootstrap: primeiro ciclo (lastAt=0) envia só se critical — evita digest spam no boot saudável.
    const criticalCooldownMs = parseInt(process.env.PIPELINE_DIGEST_CRITICAL_COOLDOWN_H || '24', 10) * 60 * 60 * 1000;
    const healthyCooldownMs = parseInt(process.env.PIPELINE_DIGEST_HEALTHY_COOLDOWN_D || '6', 10) * 24 * 60 * 60 * 1000;
    const cooldownMs = newState === 'critical' ? criticalCooldownMs : healthyCooldownMs;
    const isFirstRun = _lastPipelineDigestAt === 0;
    const withinCooldown = !isFirstRun && (Date.now() - _lastPipelineDigestAt) < cooldownMs;
    if (isFirstRun && newState === 'healthy') {
      _lastPipelineDigestAt = Date.now();
      _lastPipelineDigestState = newState;
      log('DEBUG', 'PIPELINE-DIGEST', `first-run healthy — cooldown 6d iniciado, nada enviado`);
      return;
    }
    if (withinCooldown && !wasRecovered && !wasEscalated) return;

    const prefix = wasRecovered
      ? `✅ *RECOVERED — Pipeline OK*\n_Estado voltou pra saudável._\n\n`
      : wasEscalated
        ? `🚨 *ESCALATED — Pipeline entrou em CRITICAL*\n\n`
        : newState === 'critical'
          ? `🚨 *CRITICAL — Pipeline Alert*\n\n`
          : `📬 *Weekly Pipeline Digest*\n\n`;

    const tokenForAlert = resolveAlertsToken();
    if (!tokenForAlert) return;
    for (const adminId of ADMIN_IDS) {
      const msg = prefix + txt;
      const r_ = await sendDM(tokenForAlert, adminId, msg).catch(() => ({ ok: false }));
      if (r_ && r_.ok === false) await sendDM(tokenForAlert, adminId, msg.replace(/[*_`]/g, ''), { parse_mode: undefined }).catch(() => {});
    }
    _lastPipelineDigestAt = Date.now();
    _lastPipelineDigestState = newState;
    log('INFO', 'PIPELINE-DIGEST', `DM enviado (${newState}${wasRecovered ? ',recovered' : ''}) pra ${ADMIN_IDS.size} admins`);
  } catch (e) {
    log('WARN', 'PIPELINE-DIGEST', `falhou: ${e.message}`);
  }
}

async function runModelCalibrationCycle() {
  if (_isCycleMuted('model-calibration')) { return; }
  if (!ADMIN_IDS.size) return;
  let result = null;
  try {
    const ext = require('./lib/agents-extended');
    result = await ext.runModelCalibrationWatcher(db);
  } catch (e) {
    log('WARN', 'MODEL-CALIB', `falhou: ${e.message}`);
    return;
  }
  if (!result?.ok || !result.alerts?.length) {
    log('DEBUG', 'MODEL-CALIB', `Ciclo OK — ${result?.summary?.sports_evaluated || 0} sports, 0 drift`);
    return;
  }
  // Cooldown 24h pra evitar spam diário
  if (Date.now() - _lastModelCalibAlert < 24 * 60 * 60 * 1000) return;
  _lastModelCalibAlert = Date.now();

  const tokenForAlert = resolveAlertsToken();
  if (!tokenForAlert) return;
  const lines = result.alerts.map(a => `🎯 *${a.sport.toUpperCase()}* — ${a.message}\n   └─ ${a.suggestions[0]}`).join('\n\n');
  const msg = `🎯 *MODEL CALIBRATION WATCHER (semanal)*\n\n${lines}\n\n_Próximo check em 7 dias._`;
  for (const adminId of ADMIN_IDS) await sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));

  // Auto-retrain on drift: quando um sport tem drift > 0.03 (Brier piorou 3pp em 30d vs baseline),
  // dispara runIsotonicRefreshAsync. Cooldown 24h compartilhado com refresh por freshness.
  // Desabilita via MODEL_CALIB_AUTO_RETRAIN=false.
  const autoRetrainOn = !/^(0|false|no)$/i.test(String(process.env.MODEL_CALIB_AUTO_RETRAIN || ''));
  const hasSignificantDrift = result.alerts.some(a => a.severity === 'warning');
  if (autoRetrainOn && hasSignificantDrift) {
    if (!global.__lastIsotonicRefresh || (Date.now() - global.__lastIsotonicRefresh) > 24 * 60 * 60 * 1000) {
      global.__lastIsotonicRefresh = Date.now();
      log('WARN', 'MODEL-CALIB', `Drift ≥ 0.03 detectado em ${result.alerts.length} sport(s) — disparando auto-retrain`);
      runIsotonicRefreshAsync(tokenForAlert);
    } else {
      log('INFO', 'MODEL-CALIB', 'Auto-retrain pulado (cooldown 24h)');
    }
  }
}

// ── Daily Health workflow (1x/dia 11h UTC = 8h BRT) ──
let _lastDailyHealthRun = 0;

async function runDailyHealthIfTime() {
  const now = new Date();
  const hour = now.getUTCHours();
  if (hour < 11 || hour > 12) return; // janela 11-12 UTC
  const todayKey = now.toISOString().slice(0, 10);
  if (_lastDailyHealthRun === todayKey) return;
  _lastDailyHealthRun = todayKey;

  if (!ADMIN_IDS.size) return;
  log('INFO', 'DAILY-HEALTH', 'Rodando workflow diário consolidado...');
  try {
    const orchR = await serverGet('/agents/orchestrator?workflow=daily_health').catch(() => null);
    if (!orchR?.ok) return;

    const tokenForAlert = resolveAlertsToken();
    if (!tokenForAlert) return;

    const stepsHtml = orchR.steps.map(s => `${s.ok ? '✅' : '❌'} ${s.name}${s.duration_ms ? ` (${s.duration_ms}ms)` : ''}`).join('\n');
    const ctx = orchR.context || {};
    const summary = [];
    if (ctx.weekly_review?.summary) {
      const ws = ctx.weekly_review.summary;
      summary.push(`📊 Portfolio: 🟢${ws.verdes || 0} 🟡${ws.amarelos || 0} 🔴${ws.vermelhos || 0}`);
    }
    if (ctx.bankroll_guardian?.overall) {
      const o = ctx.bankroll_guardian.overall;
      const profitR = (o.total_current - o.total_initial).toFixed(2);
      const profitStr = `${profitR >= 0 ? '+' : ''}R$${profitR}`;
      summary.push(`💰 Banca: R$${o.total_initial.toFixed(2)} → *R$${o.total_current.toFixed(2)}* (${profitStr} | growth ${o.overall_growth_pct?.toFixed(2) || '-'}% | DD ${o.overall_drawdown_pct.toFixed(2)}%)`);
    }
    if (ctx.health_sentinel?.summary) {
      const hs = ctx.health_sentinel.summary;
      summary.push(`🩻 Saúde: ${hs.critical} crit | ${hs.warning} warn | ${hs.healthy_checks} ok`);
    }
    if (ctx.cut_advisor?.summary) {
      const ca = ctx.cut_advisor.summary;
      summary.push(`✂️ Cuts: ${ca.ready_to_cut} prontos pra cortar (R$${ca.total_daily_loss_at_risk_reais}/dia em risco)`);
    }
    const msg = `🌅 *DAILY HEALTH REPORT*\n\n${summary.join('\n')}\n\n*Steps:*\n\`\`\`${stepsHtml}\`\`\`\n\n_Próximo report amanhã 8h BRT._`;
    for (const adminId of ADMIN_IDS) await sendDM(tokenForAlert, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
  } catch (e) { log('WARN', 'DAILY-HEALTH', e.message); }
}

// Live Scout gap monitor: alerta admin via Telegram quando gap (no_gameids/stats_disabled/coverage_missing/etc)
// persiste por mais que LIVE_SCOUT_ALERT_THRESHOLD_MIN. Anti-spam: cada gap key alerta uma vez por janela.
const _liveScoutGapFirstSeen = new Map(); // gapKey -> { firstTs, lastTs, info, alerted }
const LIVE_SCOUT_ALERT_THRESHOLD_MIN = parseInt(process.env.LIVE_SCOUT_ALERT_THRESHOLD_MIN || '5', 10);
const LIVE_SCOUT_ALERT_COOLDOWN_MS = parseInt(process.env.LIVE_SCOUT_ALERT_COOLDOWN_MIN || '60', 10) * 60 * 1000;
let _lastLiveScoutCheck = 0;
const LIVE_SCOUT_CHECK_INTERVAL_MS = parseInt(process.env.LIVE_SCOUT_CHECK_INTERVAL_MIN || '3', 10) * 60 * 1000;

async function checkLiveScoutGaps() {
  if (_isCycleMuted('live-scout-gaps')) { return; }
  if (!ADMIN_IDS.size) return;
  if (!/^(1|true|yes)$/i.test(String(process.env.LIVE_SCOUT_ALERTS ?? 'true'))) return;
  const now = Date.now();
  if (now - _lastLiveScoutCheck < LIVE_SCOUT_CHECK_INTERVAL_MS) return;
  _lastLiveScoutCheck = now;

  let scout = null;
  try {
    const dashboard = require('./lib/dashboard');
    scout = await dashboard.runLiveScout(`http://127.0.0.1:${process.env.PORT || 8080}`);
  } catch (e) {
    log('WARN', 'LIVE-SCOUT-ALERT', `runLiveScout falhou: ${e.message}`);
    return;
  }
  if (!scout?.ok || !Array.isArray(scout.gaps)) return;

  // Marca todos os gaps atuais
  const currentKeys = new Set();
  for (const gap of scout.gaps) {
    const primaryFlag = (gap.flags && gap.flags[0]) || 'unknown';
    const key = `${gap.sport}|${gap.matchId || gap.teams || ''}|${primaryFlag}`;
    currentKeys.add(key);
    const prev = _liveScoutGapFirstSeen.get(key);
    if (!prev) {
      _liveScoutGapFirstSeen.set(key, { firstTs: now, lastTs: now, info: gap, alerted: false, lastAlertTs: 0 });
    } else {
      prev.lastTs = now;
      prev.info = gap; // refresh com info mais recente
    }
  }

  // Limpa entradas que sumiram (gap resolvido)
  for (const [key, st] of _liveScoutGapFirstSeen.entries()) {
    if (!currentKeys.has(key)) {
      _liveScoutGapFirstSeen.delete(key);
    }
  }

  // Dispara alertas pra gaps persistentes
  const grouped = []; // agrupa pra enviar única mensagem
  for (const [key, st] of _liveScoutGapFirstSeen.entries()) {
    const ageMin = (now - st.firstTs) / 60000;
    if (ageMin < LIVE_SCOUT_ALERT_THRESHOLD_MIN) continue;
    if (st.alerted && (now - st.lastAlertTs) < LIVE_SCOUT_ALERT_COOLDOWN_MS) continue;
    st.alerted = true; st.lastAlertTs = now;
    grouped.push({ key, ageMin, ...st.info });
  }
  if (!grouped.length) return;

  // Pega bot token genérico (esports preferido)
  const sportsOrder = ['esports', 'cs', 'valorant', 'tennis', 'mma', 'football'];
  let token = null, botSport = null;
  for (const sp of sportsOrder) {
    if (SPORTS[sp]?.enabled && SPORTS[sp]?.token) { token = SPORTS[sp].token; botSport = sp; break; }
  }
  if (!token) return;

  const lines = grouped.slice(0, 12).map(g => {
    const teamsStr = g.teams || g.matchId || '?';
    const flagsStr = (g.flags || []).slice(0, 3).join(', ');
    const leagueStr = g.league ? ` (${g.league})` : '';
    return `• ${g.sport.toUpperCase()} | ${teamsStr}${leagueStr}\n  └─ ${flagsStr} | há ${g.ageMin.toFixed(1)}min`;
  }).join('\n');
  const more = grouped.length > 12 ? `\n_(+${grouped.length - 12} outros gaps)_` : '';
  const msg = `🔍 *LIVE SCOUT — ${grouped.length} gap(s) persistente(s)*\n\n${lines}${more}\n\n` +
    `_Threshold ${LIVE_SCOUT_ALERT_THRESHOLD_MIN}min | cooldown ${Math.round(LIVE_SCOUT_ALERT_COOLDOWN_MS/60000)}min/gap_`;

  for (const adminId of ADMIN_IDS) {
    await sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
  }
  // Log detalhado (server side) além do DM — facilita debug sem precisar Telegram.
  // Mostra sport|teams|flag|idade pra identificar padrão (ex: sempre no_gameids_in_ps em LPL).
  const detailLines = grouped.slice(0, 6).map(g => {
    const teamsStr = g.teams || g.matchId || '?';
    const primaryFlag = (g.flags || [])[0] || 'unknown';
    return `${g.sport}/${teamsStr}|${primaryFlag}|${g.ageMin.toFixed(1)}m`;
  }).join(' · ');
  log('WARN', 'LIVE-SCOUT-ALERT', `${grouped.length} gap(s) persistentes [${botSport}] — ${detailLines}${grouped.length > 6 ? ` (+${grouped.length - 6})` : ''}`);
}

async function checkPatchMetaStale(token) {
  if (_isCycleMuted('patch-meta-stale')) { return; }
  if (!ADMIN_IDS.size) return;
  if (Date.now() - lastPatchAlert < PATCH_ALERT_INTERVAL) return;
  const age = getPatchMetaAgeDays();
  if (age !== null && age >= 14) {
    lastPatchAlert = Date.now();
    const msg = `⚠️ *PATCH META DESATUALIZADO*\n\n` +
      `O patch meta tem *${age} dias* sem atualização.\n\n` +
      `Atualize no \`.env\`:\n` +
      `• \`LOL_PATCH_META=Patch X.XX — ...\`\n` +
      `• \`PATCH_META_DATE=YYYY-MM-DD\`\n\n` +
      `_Análises de LoL estão usando meta desatualizado!_`;
    for (const adminId of ADMIN_IDS) {
      await sendDM(token, adminId, msg).catch(e => log('WARN', 'ALERT-FAIL', `adminId=${adminId}: ${e.message}`));
    }
  }
}

