          const last = _riskAlertDedup.get(tipId) || 0;
          if (now - last < RISK_ALERT_DEDUP_MS) continue;
          _riskAlertDedup.set(tipId, now);
          const routed = _pickTokenForAlert('live_risk') || _pickTokenForAlert('system');
          const token = routed?.token;
